  const [taskSearchQuery, setTaskSearchQuery] = useState('');
  const [activeTab, setActiveTab] = useState<'entry' | 'tasks' | 'settings' | 'analytics' | 'bom' | 'missing' | 'logistics' | 'permissions' | 'inventory'>('entry');
  const [showSuccessMessage, setShowSuccessMessage] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);

  const [bomParentQuery, setBomParentQuery] = useState('');
  const [bomQuantity, setBomQuantity] = useState('');
  const [bomSelectedWorkplace, setBomSelectedWorkplace] = useState<string | null>(null);
  const [clickedBOMTasks, setClickedBOMTasks] = useState<Set<string>>(new Set());
  const [bomRequestStatus, setBomRequestStatus] = useState<'idle' | 'loading' | 'success'>('idle');
  const [displayedBomParent, setDisplayedBomParent] = useState<string | null>(null);
  const [displayedBomQuantity, setDisplayedBomQuantity] = useState<number | null>(null);

  const currentRoleId = roles.find(r => r.name === currentUserRole)?.id;
  const hasPermission = useCallback((permName: string) => {
      if (currentUserRole === 'ADMIN' && (permName === 'perm_tab_permissions' || permName === 'perm_manage_roles' || permName === 'perm_tab_settings')) {
          return true;
      }
      if (!currentRoleId) return false;
      return permissions.some(p => p.roleId === currentRoleId && p.permissionName === permName);
  }, [currentUserRole, currentRoleId, permissions]);

  const unfinishedTasksCount = tasks.filter(t => !t.isDone).length;
  const pendingRequestsCount = props.partRequests.length + props.bomRequests.length;

  const logisticsOperationsList = useMemo(() => {
      if (props.logisticsOperations && props.logisticsOperations.length > 0) {
          return props.logisticsOperations;
      }
      return [
          { id: 'op_unloading', value: t('op_unloading') },
          { id: 'op_loading', value: t('op_loading') },
          { id: 'op_putaway', value: t('op_putaway') },
          { id: 'op_move', value: t('op_move') }
      ];
  }, [props.logisticsOperations, t]);

  useEffect(() => {
      if (entryMode === 'logistics') {
          setQuantityUnit('pallet');
      } else {
          setQuantityUnit('pcs');
      }
  }, [entryMode]);

  const handleLogoutWithCheck = () => {
      const savedScans = localStorage.getItem('inventory_scans');
      if (savedScans) {
          try {
              const scans = JSON.parse(savedScans);
              if (scans.length > 0) {
                  const confirmMsg = language === 'sk' 
                    ? `Pozor! V Inventúre máte ${scans.length} neexportovaných položiek. Po odhlásení zostanú v pamäti tohto tabletu, ale odporúčame ich najskôr exportovať. Naozaj sa chcete odhlásiť?`
                    : `Warning! You have ${scans.length} unexported items in Inventory. They will remain in this tablet's memory, but we recommend exporting them first. Do you really want to log out?`;

                  if (!window.confirm(confirmMsg)) return;
              }
          } catch (e) {}
      }
      onLogout();
  };

  const handleSendToTasks = () => {
    if (entryMode === 'production') {
        if (!selectedPart || !selectedWorkplace || !quantity) {
            alert(t('fill_all_fields')); 
            return;
        }
        onAddTask(selectedPart.value, selectedWorkplace, quantity, quantityUnit, priority, 'production');
    } else {
        if (!logisticsRef || !logisticsOp || !quantity) {
            alert(t('fill_all_fields'));
            return;
        }
        onAddTask(logisticsRef, logisticsOp, quantity, quantityUnit, priority, 'logistics');
    }

    setSelectedPart(null);
    setSelectedWorkplace(null);
    setLogisticsRef('');
    setLogisticsOp('');
    setQuantity('');
    if (entryMode === 'logistics') {
         setQuantityUnit('pallet'); 
    } else {
         setQuantityUnit('pcs'); 
    }
    setPriority('NORMAL'); 
    setShowSuccessMessage(true);
    setTimeout(() => setShowSuccessMessage(false), 2000);
  };

  const handleCalculateBOM = () => {
    if (!bomParentQuery || !bomQuantity || parseFloat(bomQuantity) <= 0) {
        alert(t('bom_invalid_input')); 
        return;
    }
    setDisplayedBomParent(bomParentQuery);
    setDisplayedBomQuantity(parseFloat(bomQuantity));
    setClickedBOMTasks(new Set());
  };

  const handleCreateBOMTask = (childPart: string, qty: number) => {
    if (!bomSelectedWorkplace) {
        alert(t('select_bom_workplace'));
        return;
    }
    onAddTask(childPart, bomSelectedWorkplace, qty.toString(), 'pcs', 'NORMAL', 'production');
    setClickedBOMTasks(prev => new Set(prev).add(childPart));
  };

  const handleCreateAllBOMTasks = (results: any[]) => {
      if (!bomSelectedWorkplace) {
          alert(t('select_bom_workplace'));
          return;
      }
      results.forEach(res => {
          if (!clickedBOMTasks.has(res.childPart)) {
              handleCreateBOMTask(res.childPart, res.requiredQty);
          }
      });
  };

  const handleRequestNewBOM = async () => {
      if (!bomParentQuery) return;
      setBomRequestStatus('loading');
      const success = await props.onRequestBOM(bomParentQuery);
      if (success) {
          setBomRequestStatus('success');
          setTimeout(() => setBomRequestStatus('idle'), 3000);
      } else {
          setBomRequestStatus('idle');
      }
  };

  const handleToggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen();
      setIsFullscreen(true);
    } else {
      if (document.exitFullscreen) {
        document.exitFullscreen();
        setIsFullscreen(false);
      }
    }
  };

  const bomResults = useMemo(() => {
    if (!displayedBomParent || !displayedBomQuantity) return [];
    return bomItems
        .filter(item => item.parentPart === displayedBomParent)
        .map(item => ({
            ...item,
            requiredQty: Math.ceil(item.quantity * displayedBomQuantity)
        }));
  }, [displayedBomParent, displayedBomQuantity, bomItems]);

  return (
    <div className="flex flex-col h-screen bg-gray-900 text-white">
      {notifications.length > 0 && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 p-4">
              <div className="bg-gray-800 rounded-xl max-w-md w-full p-6 shadow-2xl border border-red-600 animate-fade-in">
                  <h3 className="text-xl font-bold text-red-400 mb-4 text-center">{t('alert_missing_title')}</h3>
                  <div className="space-y-3 max-h-60 overflow-y-auto custom-scrollbar">
                      {notifications.map(notif => (
                          <div key={notif.id} className="bg-gray-700 p-3 rounded-lg flex items-center justify-between gap-3">
                              <div>
                                  <p className="font-bold text-white text-lg font-mono">{notif.partNumber}</p>
                                  <p className="text-sm text-gray-300">{notif.reason} - <span className="text-red-400">{notif.reportedBy}</span></p>
                                  <p className="text-xs text-gray-500">{new Date(notif.timestamp).toLocaleString('sk-SK')}</p>
                              </div>
                              <button onClick={() => props.onClearNotification(notif.id)} className="text-red-300 hover:text-red-500 p-2 rounded-full hover:bg-gray-600">
                                  <CheckCircleIcon className="w-6 h-6" />
                              </button>
                          </div>
                      ))}
                  </div>
                  <button onClick={() => notifications.forEach(n => props.onClearNotification(n.id))} className="mt-6 w-full py-3 bg-red-800/50 hover:bg-red-800 text-red-100 rounded-lg font-bold transition-colors">{t('alert_btn_ok')}</button>
              </div>
          </div>
      )}

      {props.isBreakActive && (
        <div className="w-full px-2 sm:px-4 pt-2 z-50 bg-gray-900">
            <div className="w-full bg-red-600 text-white py-4 rounded-xl shadow-[0_0_20px_rgba(220,38,38,0.6)] flex items-center justify-center gap-3 animate-pulse border-2 border-red-400">
                <ClockIcon className="w-8 h-8 flex-shrink-0" />
                <span className="font-extrabold text-xl sm:text-2xl uppercase tracking-widest leading-none text-center">PREBIEHA PRESTÁVKA</span>
            </div>
        </div>
      )}

      {showSuccessMessage && (
        <div className="fixed top-20 right-4 bg-green-600 text-white p-4 rounded-lg shadow-xl z-50 animate-bounce">
          {t('sent_msg')}
        </div>
      )}

      <div className="bg-gray-900 shadow-2xl z-40 p-3 border-b border-gray-800 relative">
        <div className="max-w-7xl mx-auto w-full flex items-center justify-between relative">
          <div className="flex items-center z-10">
             <div className="flex bg-gray-800 rounded-lg p-1 border border-gray-700 shadow-inner">
                <button onClick={() => setLanguage('sk')} className={`px-3 py-1.5 rounded-md text-xs font-bold transition-all duration-200 ${language === 'sk' ? 'bg-teal-600 text-white shadow-lg' : 'text-gray-400 hover:text-white'}`}>SK</button>
                <button onClick={() => setLanguage('en')} className={`px-3 py-1.5 rounded-md text-xs font-bold transition-all duration-200 ${language === 'en' ? 'bg-teal-600 text-white shadow-lg' : 'text-gray-400 hover:text-white'}`}>EN</button>
             </div>
          </div>
          <div className="flex items-center gap-3 z-10">
            {/* User Info Pill */}
            <div className="hidden sm:flex items-center gap-2 bg-gray-800 border border-gray-700 px-3 py-1.5 rounded-full shadow-sm">
                <UserIcon className="w-4 h-4 text-teal-400" />
                <div className="flex flex-col">
                    <span className="text-xs font-black text-white leading-none truncate max-w-[120px]">{currentUser}</span>
                    <span className={`text-[9px] font-bold uppercase leading-none mt-1 ${currentUserRole === 'ADMIN' ? 'text-red-400' : currentUserRole === 'LEADER' ? 'text-sky-400' : 'text-teal-500 opacity-80'}`}>
                        {currentUserRole}
                    </span>
                </div>
            </div>

            {installPrompt && hasPermission('perm_install_pwa') && (
                <button onClick={onInstallApp} className="bg-blue-600 hover:bg-blue-500 text-white p-2 rounded-lg transition-colors shadow-md border border-blue-500/50" title={t('pwa_install_btn')}>
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor"><path d="M10 2a.75.75 0 01.75.75v6.5a.75.75 0 01-1.5 0V2.75A.75.75 0 0110 2z"/><path fillRule="evenodd" d="M3.5 9.25a.75.75 0 00-1.5 0v7a2 2 0 002 2h11a2 2 0 002-2v-7a.75.75 0 00-1.5 0v7a.5.5 0 01-.5.5h-11a.5.5 0 01-.5-.5v-7z" clipRule="evenodd"/></svg>
                </button>
            )}
            {hasPermission('perm_view_fullscreen') && (
                <button onClick={handleToggleFullscreen} className="bg-gray-700 hover:bg-gray-600 text-teal-400 hover:text-white p-2 rounded-lg transition-all shadow-md border border-gray-600" title={isFullscreen ? t('fullscreen_off') : t('fullscreen_on')}>
                    {isFullscreen ? <ExitFullscreenIcon className="h-5 w-5" /> : <FullscreenIcon className="h-5 w-5" />}
                </button>
            )}
            <button onClick={handleLogoutWithCheck} className="bg-red-600 hover:bg-red-500 text-white p-2 rounded-lg transition-all shadow-md border border-red-500/50" title={t('logout')}>
              <LogoutIcon className="h-5 w-5" />
            </button>
          </div>
        </div>
      </div>

      <div className="bg-gray-800 border-t border-gray-700 shadow-sm z-10">
        <div className="max-w-7xl mx-auto w-full px-2 sm:px-4 overflow-x-auto custom-scrollbar">
          <div className="flex space-x-4 sm:space-x-6">
            {hasPermission('perm_tab_entry') && <button onClick={() => setActiveTab('entry')} className={`whitespace-nowrap py-3 px-1 border-b-4 font-bold text-sm transition-colors ${activeTab === 'entry' ? 'border-teal-500 text-teal-400' : 'border-transparent text-gray-400 hover:text-gray-200 hover:border-gray-500'}`}>{t('tab_entry')}</button>}
            {hasPermission('perm_tab_tasks') && <button onClick={() => setActiveTab('tasks')} className={`relative whitespace-nowrap py-3 px-1 border-b-4 font-bold text-sm transition-colors ${activeTab === 'tasks' ? 'border-teal-500 text-teal-400' : 'border-transparent text-gray-400 hover:text-gray-200 hover:border-gray-500'} ${unfinishedTasksCount > 0 ? 'text-orange-400' : ''}`}>{t('tab_tasks')} {unfinishedTasksCount > 0 && <span className="ml-1 sm:ml-2 bg-orange-600 text-white text-xs rounded-full px-1.5 sm:px-2 py-0.5">{unfinishedTasksCount}</span>}</button>}
            {hasPermission('perm_tab_bom') && <button onClick={() => setActiveTab('bom')} className={`relative whitespace-nowrap py-3 px-1 border-b-4 font-bold text-sm transition-colors ${activeTab === 'bom' ? 'border-teal-500 text-teal-400' : 'border-transparent text-gray-400 hover:text-gray-200 hover:border-gray-500'}`}>{t('tab_bom')}</button>}
            {hasPermission('perm_tab_missing') && <button onClick={() => setActiveTab('missing')} className={`relative whitespace-nowrap py-3 px-1 border-b-4 font-bold text-sm transition-colors ${activeTab === 'missing' ? 'border-teal-500 text-teal-400' : 'border-transparent text-gray-400 hover:text-gray-200 hover:border-gray-500'}`}>{t('tab_missing')}</button>}
            {hasPermission('perm_tab_inventory') && <button onClick={() => setActiveTab('inventory')} className={`relative whitespace-nowrap py-3 px-1 border-b-4 font-bold text-sm transition-colors ${activeTab === 'inventory' ? 'border-teal-500 text-teal-400' : 'border-transparent text-gray-400 hover:text-gray-200 hover:border-gray-500'}`}>{t('tab_inventory')}</button>}
            {hasPermission('perm_tab_logistics_center') && <button onClick={() => setActiveTab('logistics')} className={`relative whitespace-nowrap py-3 px-1 border-b-4 font-bold text-sm transition-colors ${activeTab === 'logistics' ? 'border-teal-500 text-teal-400' : 'border-transparent text-gray-400 hover:text-gray-200 hover:border-gray-500'}`}>{t('tab_logistics_center')}</button>}
            {hasPermission('perm_tab_analytics') && <button onClick={() => setActiveTab('analytics')} className={`whitespace-nowrap py-3 px-1 border-b-4 font-bold text-sm transition-colors ${activeTab === 'analytics' ? 'border-teal-500 text-teal-400' : 'border-transparent text-gray-400 hover:text-gray-200 hover:border-gray-500'}`}>{t('tab_analytics')}</button>}
            {hasPermission('perm_tab_settings') && <button onClick={() => setActiveTab('settings')} className={`relative whitespace-nowrap py-3 px-1 border-b-4 font-bold text-sm transition-colors ${activeTab === 'settings' ? 'border-teal-500 text-teal-400' : 'border-transparent text-gray-400 hover:text-gray-200 hover:border-gray-500'} ${pendingRequestsCount > 0 ? 'text-red-400' : ''}`}>{t('tab_settings')} {pendingRequestsCount > 0 && <span className="ml-1 sm:ml-2 bg-red-500 text-white text-xs rounded-full px-1.5 sm:px-2 py-0.5">{pendingRequestsCount}</span>}</button>}
            {hasPermission('perm_tab_permissions') && <button onClick={() => setActiveTab('permissions')} className={`whitespace-nowrap py-3 px-1 border-b-4 font-bold text-sm transition-colors ${activeTab === 'permissions' ? 'border-teal-500 text-teal-400' : 'border-transparent text-gray-400 hover:text-gray-200 hover:border-gray-500'}`}>{t('tab_permissions')}</button>}
          </div>
        </div>
      </div>

      <div className="flex-grow overflow-y-auto p-2 md:p-6 custom-scrollbar">
        <div className="max-w-7xl mx-auto w-full h-full">
          {activeTab === 'entry' && hasPermission('perm_tab_entry') && (
            <div className="h-full flex flex-col items-center animate-fade-in pb-20">
                <div className="w-full max-w-2xl">
                    <div className="bg-gray-800 p-4 sm:p-6 rounded-xl shadow-lg border border-gray-700 relative overflow-hidden">
                        {hasPermission('perm_logistics_mode') && (
                             <div className="flex justify-center mb-6 z-10 relative">
                                <div className="bg-gray-900 p-1 rounded-lg flex border border-gray-600 shadow-inner">
                                    <button onClick={() => setEntryMode('production')} className={`px-4 sm:px-6 py-2 rounded-md font-bold text-sm sm:text-base transition-all duration-200 flex items-center gap-2 ${entryMode === 'production' ? 'bg-teal-600 text-white shadow-lg' : 'text-gray-400 hover:text-white'}`}>🏭 {t('mode_production')}</button>
                                    <button onClick={() => setEntryMode('logistics')} className={`px-4 sm:px-6 py-2 rounded-md font-bold text-sm sm:text-base transition-all duration-200 flex items-center gap-2 ${entryMode === 'logistics' ? 'bg-sky-600 text-white shadow-lg' : 'text-gray-400 hover:text-white'}`}>🚛 {t('mode_logistics')}</button>
                                </div>
                             </div>
                        )}
                        <h1 className={`text-2xl sm:text-3xl font-extrabold text-center mb-2 ${entryMode === 'production' ? 'text-teal-400' : 'text-sky-400'}`}>{t('search_title')}</h1>
                        <p className="text-gray-400 text-center mb-6 text-sm">{t('search_subtitle')}</p>
                        <div className="space-y-4 sm:space-y-6">
                            {entryMode === 'production' ? (
                                <>
                                    <div>
                                        <label className="block text-gray-300 text-sm font-bold mb-2 uppercase tracking-wide">{t('part_number')}</label>
                                        <PartNumberInput parts={parts.map(p => p.value)} onPartSelect={(p) => setSelectedPart(p ? (parts.find(i => i.value === p) || null) : null)} placeholder={t('part_placeholder')} value={selectedPart ? selectedPart.value : ''} onRequestPart={props.onRequestPart} />
                                    </div>
                                    <div>
                                        <label className="block text-gray-300 text-sm font-bold mb-2 uppercase tracking-wide">{t('workplace')}</label>
                                        <div className="relative">
                                            <select value={selectedWorkplace || ''} onChange={(e) => setSelectedWorkplace(e.target.value)} className="block appearance-none w-full bg-gray-700 border border-gray-600 text-white py-3 px-4 pr-8 rounded-lg focus:outline-none focus:ring-2 focus:ring-teal-500 focus:border-teal-500 transition-colors">
                                                <option value="">{t('workplace_placeholder')}</option>
                                                {workplaces.map((wp) => (<option key={wp.id} value={wp.value}>{wp.value}</option>))}
                                            </select>
                                        </div>
                                    </div>
                                </>
                            ) : (
                                <>
                                    <div>
                                        <label className="block text-gray-300 text-sm font-bold mb-2 uppercase tracking-wide">{t('log_reference')}</label>
                                        <input type="text" value={logisticsRef} onChange={(e) => setLogisticsRef(e.target.value)} placeholder={t('log_reference_place')} className="w-full pl-4 pr-4 py-3 bg-gray-700 border border-gray-600 rounded-lg text-white placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-sky-500 focus:border-sky-500 transition-colors" />
                                    </div>
                                    <div>
                                        <label className="block text-gray-300 text-sm font-bold mb-2 uppercase tracking-wide">{t('log_operation')}</label>
                                        <div className="relative">
                                            <select value={logisticsOp} onChange={(e) => setLogisticsOp(e.target.value)} className="block appearance-none w-full bg-gray-700 border border-gray-600 text-white py-3 px-4 pr-8 rounded-lg focus:outline-none focus:ring-2 focus:ring-sky-500 focus:border-sky-500 transition-colors">
                                                <option value="">{t('workplace_placeholder')}</option>
                                                {logisticsOperationsList.map((op) => (<option key={op.id} value={op.value}>{op.value}</option>))}
                                            </select>
                                        </div>
                                    </div>
                                </>
                            )}
                            <div>
                                <label className="block text-gray-300 text-sm font-bold mb-2 uppercase tracking-wide">{t('quantity')}</label>
                                <div className="flex flex-col sm:flex-row gap-3">
                                    <input type="number" inputMode="decimal" value={quantity} onChange={(e) => setQuantity(e.target.value)} className={`w-full sm:w-1/2 px-4 py-3 bg-gray-700 border border-gray-600 rounded-lg text-white text-lg font-mono placeholder-gray-400 focus:outline-none focus:ring-2 transition-colors ${entryMode === 'production' ? 'focus:ring-teal-500' : 'focus:ring-sky-500'}`} placeholder={t('pcs_placeholder')} />
                                    <div className="flex w-full sm:w-1/2 bg-gray-700 rounded-lg p-1 border border-gray-600">
                                        <button onClick={() => setQuantityUnit('pcs')} disabled={entryMode === 'logistics'} className={`flex-1 py-2 rounded text-sm font-bold transition-all ${quantityUnit === 'pcs' ? 'bg-gray-600 text-white shadow-md' : 'text-gray-400 hover:text-white'} ${entryMode === 'logistics' ? 'opacity-30 cursor-not-allowed' : ''}`}>{t('unit_pcs_short')}</button>
                                        <button onClick={() => setQuantityUnit('boxes')} className={`flex-1 py-2 rounded text-sm font-bold transition-all ${quantityUnit === 'boxes' ? 'bg-gray-600 text-white shadow-md' : 'text-gray-400 hover:text-white'}`}>{t('unit_boxes_short')}</button>
                                        <button onClick={() => setQuantityUnit('pallet')} className={`flex-1 py-2 rounded text-sm font-bold transition-all ${quantityUnit === 'pallet' ? 'bg-gray-600 text-white shadow-md' : 'text-gray-400 hover:text-white'}`}>{t('unit_pallet_short')}</button>
                                    </div>
                                </div>
                            </div>
                            <div>
                                <label className="block text-gray-300 text-sm font-bold mb-2 uppercase tracking-wide">{t('priority_label')}</label>
                                <div className="flex bg-gray-700 rounded-lg p-1 border border-gray-600">
                                    <button onClick={() => setPriority('LOW')} className={`flex-1 py-2 rounded text-sm font-bold transition-all ${priority === 'LOW' ? 'bg-blue-600 text-white shadow-md' : 'text-gray-400 hover:text-white'}`}>{t('prio_low')}</button>
                                    <button onClick={() => setPriority('NORMAL')} className={`flex-1 py-2 rounded text-sm font-bold transition-all ${priority === 'NORMAL' ? 'bg-green-600 text-white shadow-md' : 'text-gray-400 hover:text-white'}`}>{t('prio_normal')}</button>
                                    <button onClick={() => setPriority('URGENT')} className={`flex-1 py-2 rounded text-sm font-bold transition-all ${priority === 'URGENT' ? 'bg-red-600 text-white shadow-md animate-pulse' : 'text-gray-400 hover:text-white'}`}>{t('prio_urgent')}</button>
                                </div>
                            </div>
                            <div className="flex flex-col sm:flex-row gap-4 pt-4">
                                <button onClick={handleSendToTasks} className={`w-full text-white font-bold py-4 px-6 rounded-xl shadow-lg transform transition-all duration-150 active:scale-95 flex items-center justify-center gap-2 ${entryMode === 'production' ? 'bg-teal-600 hover:bg-teal-500 shadow-[0_0_15px_rgba(13,148,136,0.4)]' : 'bg-sky-600 hover:bg-sky-500 shadow-[0_0_15px_rgba(14,165,233,0.4)]'}`}>
                                    <PlusIcon className="w-6 h-6" />
                                    {t('send_btn')}
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
          )}

          {activeTab === 'tasks' && hasPermission('perm_tab_tasks') && (
            <div className="animate-fade-in pb-20">
              <div className="mb-4 flex justify-center">
                  <input type="text" value={taskSearchQuery} onChange={e => setTaskSearchQuery(e.target.value)} className="w-full max-w-md px-4 py-2 bg-gray-800 border border-gray-700 rounded-lg text-white placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-teal-500 transition-all" placeholder={t('task_search_placeholder')} />
              </div>
              <TaskList currentUser={currentUserRole} currentUserName={currentUser} tasks={tasks.filter(t => { const q = taskSearchQuery.toLowerCase(); return (t.partNumber && t.partNumber.toLowerCase().includes(q)) || (t.text && t.text.toLowerCase().includes(q)) || (t.workplace && t.workplace.toLowerCase().includes(q)); })} onToggleTask={onToggleTask} onEditTask={onEditTask} onDeleteTask={onDeleteTask} onToggleMissing={onToggleMissing} onSetInProgress={onSetInProgress} onToggleBlock={onToggleBlock} onToggleManualBlock={onToggleManualBlock} onMarkAsIncorrect={onMarkAsIncorrect} onAddNote={onAddNote} onReleaseTask={onReleaseTask} missingReasons={missingReasons} hasPermission={hasPermission} />
            </div>
          )}

          {activeTab === 'analytics' && hasPermission('perm_tab_analytics') && <AnalyticsTab tasks={tasks} onFetchArchivedTasks={props.onFetchArchivedTasks} systemBreaks={props.systemBreaks} />}
          {activeTab === 'settings' && hasPermission('perm_tab_settings') && <SettingsTab currentUserRole={currentUserRole} users={users} onAddUser={props.onAddUser} onUpdatePassword={props.onUpdatePassword} onUpdateUserRole={props.onUpdateUserRole} onDeleteUser={props.onDeleteUser} parts={parts} workplaces={workplaces} missingReasons={missingReasons} onAddPart={props.onAddPart} onBatchAddParts={props.onBatchAddParts} onDeletePart={props.onDeletePart} onDeleteAllParts={props.onDeleteAllParts} onAddWorkplace={props.onAddWorkplace} onBatchAddWorkplaces={props.onBatchAddWorkplaces} onDeleteWorkplace={props.onDeleteWorkplace} onDeleteAllWorkplaces={props.onDeleteAllWorkplaces} onAddMissingReason={props.onAddMissingReason} onDeleteMissingReason={props.onDeleteMissingReason} logisticsOperations={logisticsOperationsList} onAddLogisticsOperation={props.onAddLogisticsOperation} onDeleteLogisticsOperation={props.onDeleteLogisticsOperation} partRequests={props.partRequests} onApprovePartRequest={onApprovePartRequest} onRejectPartRequest={onRejectPartRequest} onArchiveTasks={onArchiveTasks} breakSchedules={breakSchedules} onAddBreakSchedule={props.onAddBreakSchedule} onDeleteBreakSchedule={props.onDeleteBreakSchedule} bomItems={bomItems} bomRequests={bomRequests} onAddBOMItem={props.onAddBOMItem} onBatchAddBOMItems={props.onBatchAddBOMItems} onDeleteBOMItem={props.onDeleteBOMItem} onDeleteAllBOMItems={props.onDeleteAllBOMItems} onApproveBOMRequest={onApproveBOMRequest} onRejectBOMRequest={onRejectBOMRequest} roles={roles} permissions={permissions} onAddRole={onAddRole} onDeleteRole={onDeleteRole} onUpdatePermission={onUpdatePermission} installPrompt={installPrompt} onInstallApp={onInstallApp} systemConfig={systemConfig} onUpdateSystemConfig={onUpdateSystemConfig} dbLoadWarning={dbLoadWarning} />}

          {activeTab === 'bom' && hasPermission('perm_tab_bom') && (
              <div className="h-full animate-fade-in pb-20">
                  <div className="max-w-7xl mx-auto">
                      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

                          {/* PANEL VSTUPOV */}
                          <div className="lg:col-span-4 space-y-6">
                              <div className="bg-gray-800 p-6 rounded-2xl shadow-xl border border-gray-700">
                                  <div className="flex items-center gap-3 mb-6">
                                      <div className="p-2 bg-teal-500/20 rounded-lg">
                                          <ClipboardListIcon className="w-6 h-6 text-teal-400" />
                                      </div>
                                      <h2 className="text-xl font-bold text-white">{t('bom_title')}</h2>
                                  </div>

                                  <div className="space-y-4">
                                      <div>
                                          <label className="block text-gray-400 text-xs font-bold mb-2 uppercase tracking-wider">{t('bom_parent')}</label>
                                          <PartNumberInput 
                                              parts={parts.map(p => p.value)} 
                                              value={bomParentQuery} 
                                              onInputChange={(val) => setBomParentQuery(val)} 
                                              onPartSelect={(val) => { if (val) setBomParentQuery(val); }} 
                                              placeholder={t('part_placeholder')} 
                                          />
                                      </div>
                                      <div>
                                          <label className="block text-gray-400 text-xs font-bold mb-2 uppercase tracking-wider">{t('bom_qty')}</label>
                                          <input 
                                              type="number" 
                                              inputMode="numeric"
                                              value={bomQuantity} 
                                              onChange={(e) => setBomQuantity(e.target.value)} 
                                              className="w-full px-4 py-3 bg-gray-700 border border-gray-600 rounded-xl text-white font-mono placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-teal-500 transition-all" 
                                              placeholder="Napr. 500" 
                                          />
                                      </div>
                                      <div>
                                          <label className="block text-gray-400 text-xs font-bold mb-2 uppercase tracking-wider">{t('bom_select_wp')}</label>
                                          <select 
                                              value={bomSelectedWorkplace || ''} 
                                              onChange={(e) => setBomSelectedWorkplace(e.target.value)} 
                                              className="w-full px-4 py-3 bg-gray-700 border border-gray-600 rounded-xl text-white focus:outline-none focus:ring-2 focus:ring-teal-500 transition-all"
                                          >
                                              <option value="">{t('workplace_placeholder')}</option>
                                              {workplaces.map(wp => <option key={wp.id} value={wp.value}>{wp.value}</option>)}
                                          </select>
                                      </div>

                                      <button 
                                          onClick={handleCalculateBOM} 
                                          className="w-full bg-teal-600 hover:bg-teal-500 text-white font-bold py-4 rounded-xl shadow-lg shadow-teal-900/20 transform transition-all active:scale-95 flex items-center justify-center gap-2"
                                      >
                                          <ActivityIcon className="h-5 w-5" />
                                          {t('bom_calc_btn')}
                                      </button>

                                      {bomParentQuery && bomResults.length === 0 && (
                                          <button 
                                              onClick={handleRequestNewBOM}
                                              disabled={bomRequestStatus !== 'idle'}
                                              className={`w-full py-3 rounded-xl border text-sm font-bold transition-all ${
                                                  bomRequestStatus === 'success' ? 'bg-green-600 border-green-500 text-white' : 
                                                  bomRequestStatus === 'loading' ? 'bg-gray-700 border-gray-600 text-gray-400 animate-pulse' :
                                                  'bg-gray-800 border-gray-600 text-gray-300 hover:bg-gray-700'
                                              }`}
                                          >
                                              {bomRequestStatus === 'loading' ? '...' : bomRequestStatus === 'success' ? t('bom_req_success') : t('bom_request_btn')}
                                          </button>
                                      )}
                                  </div>
                              </div>

                              {bomResults.length > 0 && (
                                  <div className="grid grid-cols-2 gap-4">
                                      <div className="bg-gray-800 p-4 rounded-xl border border-gray-700">
                                          <p className="text-gray-500 text-[10px] font-bold uppercase tracking-widest">{language === 'sk' ? 'Komponenty' : 'Components'}</p>
                                          <p className="text-2xl font-black text-white">{bomResults.length}</p>
                                      </div>
                                      <div className="bg-gray-800 p-4 rounded-xl border border-gray-700">
                                          <p className="text-gray-500 text-[10px] font-bold uppercase tracking-widest">{language === 'sk' ? 'Zostáva' : 'Remaining'}</p>
                                          <p className="text-2xl font-black text-orange-400">{bomResults.length - clickedBOMTasks.size}</p>
                                      </div>
                                  </div>
                              )}
                          </div>

                          {/* PANEL VÝSLEDKOV */}
                          <div className="lg:col-span-8">
                              {bomResults.length > 0 ? (
                                  <div className="bg-gray-800 rounded-2xl shadow-xl border border-gray-700 overflow-hidden flex flex-col h-full">
                                      <div className="p-6 border-b border-gray-700 flex justify-between items-center bg-gray-900/30">
                                          <div>
                                              <h3 className="text-xl font-bold text-white font-mono uppercase">
                                                  {displayedBomParent}
                                              </h3>
                                              <p className="text-sm text-gray-500">
                                                  {t('bom_results')} <span className="text-teal-400 font-bold">{displayedBomQuantity} ks</span>
                                              </p>
                                          </div>
                                          <button 
                                              onClick={() => handleCreateAllBOMTasks(bomResults)}
                                              className="bg-sky-600 hover:bg-sky-500 text-white px-5 py-2.5 rounded-xl text-sm font-bold shadow-lg transition-all active:scale-95 flex items-center gap-2"
                                          >
                                              🚀 {language === 'sk' ? 'Odoslať Všetko' : 'Send All'}
                                          </button>
                                      </div>

                                      <div className="overflow-x-auto flex-grow custom-scrollbar">
                                          <table className="w-full text-left">
                                              <thead className="bg-gray-900/50 text-gray-400 text-[10px] font-bold uppercase tracking-widest border-b border-gray-700">
                                                  <tr>
                                                      <th className="py-4 px-6">{t('bom_child')}</th>
                                                      <th className="py-4 px-6 text-center">{language === 'sk' ? 'Spotreba/ks' : 'Usage/pc'}</th>
                                                      <th className="py-4 px-6 text-right">{t('bom_req_qty')}</th>
                                                      <th className="py-4 px-6 text-center">{language === 'sk' ? 'Akcia' : 'Action'}</th>
                                                  </tr>
                                              </thead>
                                              <tbody className="divide-y divide-gray-700/50">
                                                  {bomResults.map((res) => {
                                                      const isSent = clickedBOMTasks.has(res.childPart);
                                                      return (
                                                          <tr key={res.childPart} className={`transition-colors ${isSent ? 'bg-teal-500/5 opacity-60' : 'hover:bg-gray-700/30'}`}>
                                                              <td className="py-5 px-6">
                                                                  <p className={`font-mono font-bold ${isSent ? 'text-gray-500' : 'text-white'}`}>{res.childPart}</p>
                                                                  <p className="text-[10px] text-gray-500">Standard Component</p>
                                                              </td>
                                                              <td className="py-5 px-6 text-center text-gray-400 font-mono text-xs">
                                                                  {res.quantity}
                                                              </td>
                                                              <td className="py-5 px-6 text-right">
                                                                  <span className={`text-lg font-bold font-mono ${isSent ? 'text-gray-500' : 'text-teal-400'}`}>
                                                                      {res.requiredQty} <span className="text-xs font-normal">ks</span>
                                                                  </span>
                                                              </td>
                                                              <td className="py-5 px-6 text-center">
                                                                  <button 
                                                                      onClick={() => !isSent && handleCreateBOMTask(res.childPart, res.requiredQty)}
                                                                      disabled={isSent}
                                                                      className={`inline-flex items-center justify-center p-2 rounded-lg transition-all ${
                                                                          isSent ? 'bg-gray-700 text-teal-500' : 'bg-teal-600/20 text-teal-400 hover:bg-teal-600 hover:text-white'
                                                                      }`}
                                                                  >
                                                                      {isSent ? <CheckCircleIcon className="w-6 h-6" /> : <PlusIcon className="w-6 h-6" />}
                                                                  </button>
                                                              </td>
                                                          </tr>
                                                      );
                                                  })}
                                              </tbody>
                                          </table>
                                      </div>
                                  </div>
                              ) : (
                                  <div className="h-full flex flex-col items-center justify-center bg-gray-800/50 rounded-2xl border-2 border-dashed border-gray-700 p-12 text-center">
                                      <div className="w-20 h-20 bg-gray-700 rounded-full flex items-center justify-center mb-6">
                                          <SearchIcon className="w-10 h-10 text-gray-500" />
                                      </div>
                                      <h3 className="text-xl font-bold text-gray-400 mb-2">{language === 'sk' ? 'Žiadne dáta na zobrazenie' : 'No data to display'}</h3>
                                      <p className="text-gray-500 max-w-xs">{language === 'sk' ? 'Zadajte číslo výrobku a plánované množstvo pre výpočet potrebného materiálu.' : 'Enter product number and planned quantity to calculate required material.'}</p>
                                  </div>
                              )}
                          </div>

                      </div>
                  </div>
              </div>
          )}
           {activeTab === 'missing' && hasPermission('perm_tab_missing') && <MissingItemsTab tasks={tasks} onDeleteMissingItem={props.onDeleteMissingItem} hasPermission={hasPermission} />}
           {activeTab === 'inventory' && hasPermission('perm_tab_inventory') && <InventoryTab currentUser={currentUser} tasks={tasks} onDeleteTask={props.onDeleteTask} hasPermission={hasPermission} parts={parts.map(p => p.value)} onRequestPart={props.onRequestPart} />}
           {activeTab === 'logistics' && hasPermission('perm_tab_logistics_center') && <LogisticsCenterTab tasks={tasks} onDeleteTask={props.onDeleteTask} hasPermission={hasPermission} />}
           {activeTab === 'permissions' && hasPermission('perm_tab_permissions') && <PermissionsTab roles={roles} permissions={permissions} onAddRole={onAddRole} onDeleteRole={onDeleteRole} onUpdatePermission={onUpdatePermission} onVerifyAdminPassword={onVerifyAdminPassword} />}
        </div>
      </div>
    </div>
  );
};

export default PartSearchScreen;

import React, { useState, useEffect, useRef } from 'react';
import { useLanguage } from './LanguageContext';
import PartNumberInput from './PartNumberInput';

interface ScannedItem {
    id: string;
    location: string;
    partNumber: string;
    batch: string;
    quantity: string;
    timestamp: number;
    worker: string;
}

interface InventoryTabProps {
    currentUser: string;
    tasks: any[];
    onDeleteTask: (id: string) => void;
    hasPermission: (perm: string) => boolean;
    parts: string[];
    onRequestPart: (part: string) => Promise<boolean>;
}

declare var XLSX: any;

const InventoryTab: React.FC<InventoryTabProps> = ({ currentUser, parts, onRequestPart }) => {
    const { t, language } = useLanguage();

    const locationRef = useRef<HTMLInputElement>(null);
    const partRef = useRef<HTMLInputElement>(null);
    const batchRef = useRef<HTMLInputElement>(null);
    const quantityRef = useRef<HTMLInputElement>(null);

    const [location, setLocation] = useState('');
    const [partNumber, setPartNumber] = useState('');
    const [batch, setBatch] = useState('');
    const [quantity, setQuantity] = useState('');
    const [lastSaved, setLastSaved] = useState<number | null>(null);
    const [scannedItems, setScannedItems] = useState<ScannedItem[]>([]);

    // --- LOCAL TIME TRACKING (ZERO FIREBASE IMPACT) ---
    useEffect(() => {
        const HEARTBEAT_MS = 30000; // 30 sekúnd
        const timer = setInterval(() => {
            if (!currentUser) return;

            const today = new Date().toISOString().slice(0, 10);
            const rawLogs = localStorage.getItem('inventory_work_logs');
            let logs = rawLogs ? JSON.parse(rawLogs) : [];

            // Hľadáme dnešný záznam pre tohto pracovníka
            const logIndex = logs.findIndex((l: any) => l.worker === currentUser && l.date === today);

            if (logIndex > -1) {
                logs[logIndex].durationMs += HEARTBEAT_MS;
            } else {
                logs.push({
                    worker: currentUser,
                    date: today,
                    durationMs: HEARTBEAT_MS
                });
            }

            // Uložíme späť do localStorage (limitujeme históriu na 31 dní kvôli pamäti)
            const oneMonthAgo = new Date();
            oneMonthAgo.setDate(oneMonthAgo.getDate() - 31);
            const filteredLogs = logs.filter((l: any) => new Date(l.date) > oneMonthAgo);

            localStorage.setItem('inventory_work_logs', JSON.stringify(filteredLogs));
        }, HEARTBEAT_MS);

        return () => clearInterval(timer);
    }, [currentUser]);

    useEffect(() => {
        const saved = localStorage.getItem('inventory_scans');
        if (saved) {
            try {
                const parsed = JSON.parse(saved);
                setScannedItems(parsed);
                if (parsed.length > 0) {
                    setLastSaved(parsed[0].timestamp);
                }
            } catch (e) {
                console.error("Failed to parse inventory scans", e);
            }
        }
    }, []);

    useEffect(() => {
        localStorage.setItem('inventory_scans', JSON.stringify(scannedItems));
        if (scannedItems.length > 0) {
            setLastSaved(Date.now());
        }
    }, [scannedItems]);

    const handleLocationChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        setLocation(e.target.value.toUpperCase());
    };

    const handleBatchChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const val = e.target.value.replace(/\D/g, '');
        if (val.length <= 7) setBatch(val);
    };

    const handleQuantityChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const val = e.target.value.replace(/[^0-9.,]/g, '');
        if (val.length <= 8) setQuantity(val);
    };

    const handleAddItem = () => {
        if (!location || !partNumber || !quantity) {
            alert(language === 'sk' ? "Vyplňte kľúčové údaje (Lokácia, Diel, Množstvo)." : "Fill required data (Location, Part, Qty).");
            return;
        }
        const newItem: ScannedItem = {
            id: crypto.randomUUID(),
            location,
            partNumber,
            batch,
            quantity,
            timestamp: Date.now(),
            worker: currentUser
        };
        setScannedItems([newItem, ...scannedItems]);
        setLocation(''); setPartNumber(''); setBatch(''); setQuantity('');
        setTimeout(() => locationRef.current?.focus(), 10);
    };

    const handleKeyDown = (e: React.KeyboardEvent, nextRef: React.RefObject<HTMLInputElement | null>) => {
        if (e.key === 'Enter') { e.preventDefault(); nextRef.current?.focus(); }
    };

    const handleDeleteItem = (id: string) => {
        setScannedItems(scannedItems.filter(item => item.id !== id));
    };

    const handleClearAll = () => {
        if (window.confirm(language === 'sk' ? "Naozaj chcete vymazať celý zoznam?" : "Really clear all items?")) {
            setScannedItems([]);
            localStorage.removeItem('inventory_scans');
            setLastSaved(null);
        }
    };

    const handleExport = () => {
        if (scannedItems.length === 0) return;
        if (typeof XLSX === 'undefined') { alert("Library Error"); return; }
        const data = scannedItems.map(item => ({
            "Dátum inventúry": new Date(item.timestamp).toLocaleDateString('sk-SK'),
            "Užívateľ": item.worker,
            "Lokácia": item.location,
            "Číslo dielu": item.partNumber,
            "Batch": item.batch,
            "Množstvo": item.quantity,
            "Presný čas": new Date(item.timestamp).toLocaleTimeString('sk-SK')
        }));
        const ws = XLSX.utils.json_to_sheet(data);
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, "Inventúra");
        XLSX.writeFile(wb, `Inventura_${new Date().toISOString().slice(0, 10)}.xlsx`);
    };

    return (
        <div className="max-w-4xl mx-auto space-y-6 pb-20 animate-fade-in">
            <div className="bg-gray-800 p-6 rounded-xl shadow-lg border border-gray-700 relative overflow-hidden">
                {/* Visual Indicator of Timer */}
                <div className="absolute top-4 right-4 flex items-center gap-2">
                    <div className="w-2 h-2 bg-blue-500 rounded-full animate-pulse shadow-[0_0_8px_rgba(59,130,246,0.8)]"></div>
                    <span className="text-[10px] font-bold text-blue-400 uppercase tracking-widest">Auto-tracker aktívny</span>
                </div>

                <div className="flex justify-between items-center mb-8">
                    <div>
                        <h1 className="text-3xl font-extrabold text-[#4169E1] uppercase tracking-widest leading-none">
                            {t('tab_inventory')}
                        </h1>
                        <div className="flex gap-4 items-center mt-2">
                            {lastSaved && (
                                <p className="text-[10px] text-gray-500 uppercase font-mono">
                                    {language === 'sk' ? 'Uložené:' : 'Saved:'} {new Date(lastSaved).toLocaleTimeString()}
                                </p>
                            )}
                            <p className="text-[10px] text-teal-500 uppercase font-mono">
                                {language === 'sk' ? 'Užívateľ:' : 'User:'} {currentUser}
                            </p>
                        </div>
                    </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div>
                        <label className="block text-gray-400 text-sm font-bold mb-2 uppercase tracking-tighter">Lokácia</label>
                        <input 
                            ref={locationRef}
                            type="text"
                            value={location}
                            onChange={handleLocationChange}
                            onKeyDown={(e) => handleKeyDown(e, partRef)}
                            placeholder={language === 'sk' ? "Zadaj lokáciu..." : "Enter location..."}
                            className="w-full bg-gray-700 border border-gray-600 rounded-lg px-4 py-3 text-white placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-[#4169E1] transition-all font-mono uppercase"
                        />
                    </div>
                    <div>
                        <label className="block text-gray-400 text-sm font-bold mb-2 uppercase tracking-tighter">Číslo dielu</label>
                        <PartNumberInput 
                            inputRef={partRef}
                            parts={parts}
                            onPartSelect={(p) => setPartNumber(p || '')}
                            onInputChange={(val) => setPartNumber(val.toUpperCase())}
                            onKeyDown={(e) => handleKeyDown(e, batchRef)}
                            placeholder={t('part_placeholder')}
                            value={partNumber}
                            onRequestPart={onRequestPart}
                        />
                    </div>
                    <div>
                        <label className="block text-gray-400 text-sm font-bold mb-2 uppercase tracking-tighter">Batch</label>
                        <input 
                            ref={batchRef}
                            type="text"
                            inputMode="numeric"
                            value={batch}
                            onChange={handleBatchChange}
                            onKeyDown={(e) => handleKeyDown(e, quantityRef)}
                            placeholder={language === 'sk' ? "Zadaj batch..." : "Enter batch..."}
                            className="w-full bg-gray-700 border border-gray-600 rounded-lg px-4 py-3 text-white placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-[#4169E1] transition-all font-mono"
                        />
                    </div>
                    <div>
                        <label className="block text-gray-400 text-sm font-bold mb-2 uppercase tracking-tighter">Množstvo</label>
                        <input 
                            ref={quantityRef}
                            type="text"
                            inputMode="decimal"
                            value={quantity}
                            onChange={handleQuantityChange}
                            onKeyDown={(e) => e.key === 'Enter' && handleAddItem()}
                            placeholder={t('pcs_placeholder')}
                            className="w-full bg-gray-700 border border-gray-600 rounded-lg px-4 py-3 text-white placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-[#4169E1] transition-all font-mono"
                        />
                    </div>
                </div>

                <button 
                    onClick={handleAddItem}
                    className="w-full mt-8 bg-[#4169E1] hover:bg-[#3151b1] text-white font-bold py-4 rounded-xl shadow-lg transition-all active:scale-95 uppercase tracking-widest"
                >
                    Pridať do zoznamu
                </button>
            </div>

            <div className="bg-gray-800 rounded-xl shadow-lg border border-gray-700 overflow-hidden">
                <div className="p-4 border-b border-gray-700 bg-gray-900/50 flex justify-between items-center">
                    <div className="flex items-center gap-2">
                        <h3 className="text-gray-400 font-bold uppercase text-sm tracking-widest">Naskenované položky</h3>
                        <span className="bg-gray-700 text-white text-xs px-2 py-1 rounded-full font-mono">{scannedItems.length}</span>
                    </div>
                    <div className="flex gap-2">
                        <button onClick={handleClearAll} className="bg-red-900/50 hover:bg-red-800 text-red-200 px-3 py-1.5 rounded-lg text-xs font-bold border border-red-800 transition-colors">Vymazať zoznam</button>
                        <button onClick={handleExport} className="bg-green-700 hover:bg-green-600 text-white px-3 py-1.5 rounded-lg text-xs font-bold shadow-md transition-colors flex items-center gap-1.5">
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-3.5 w-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                            {t('export_excel')}
                        </button>
                    </div>
                </div>
                <div className="overflow-x-auto">
                    <table className="w-full text-left text-sm">
                        <thead className="bg-gray-900/30 text-gray-500 border-b border-gray-700">
                            <tr>
                                <th className="py-3 px-4">Dátum</th>
                                <th className="py-3 px-4">Užívateľ</th>
                                <th className="py-3 px-4">Lokácia</th>
                                <th className="py-3 px-4">Diel</th>
                                <th className="py-3 px-4">Batch</th>
                                <th className="py-3 px-4 text-right">Množstvo</th>
                                <th className="py-3 px-4 text-center">Akcia</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-700">
                            {scannedItems.length > 0 ? (
                                scannedItems.map(item => (
                                    <tr key={item.id} className="text-gray-300 hover:bg-gray-700/30 transition-colors">
                                        <td className="py-3 px-4 text-[10px] text-gray-500 whitespace-nowrap">{new Date(item.timestamp).toLocaleDateString('sk-SK')}<br/>{new Date(item.timestamp).toLocaleTimeString('sk-SK')}</td>
                                        <td className="py-3 px-4 text-xs font-bold text-teal-500">{item.worker}</td>
                                        <td className="py-3 px-4 font-mono font-bold text-teal-400">{item.location}</td>
                                        <td className="py-3 px-4 font-mono">{item.partNumber}</td>
                                        <td className="py-3 px-4 font-mono">{item.batch || '-'}</td>
                                        <td className="py-3 px-4 font-bold text-white text-right">{item.quantity}</td>
                                        <td className="py-3 px-4 text-center">
                                            <button onClick={() => handleDeleteItem(item.id)} className="text-red-500 hover:text-red-400 p-2">
                                                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M9 2a1 1 0 00-.894.553L7.382 4H4a1 1 0 000 2v10a2 2 0 002 2h8a2 2 0 002-2V6a1 1 0 100-2h-3.382l-.724-1.447A1 1 0 0011 2H9zM7 8a1 1 0 012 0v6a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v6a1 1 0 102 0V8a1 1 0 00-1-1z" clipRule="evenodd" /></svg>
                                            </button>
                                        </td>
                                    </tr>
                                ))
                            ) : (
                                <tr><td colSpan={7} className="py-8 text-center text-gray-600 italic">Zoznam je prázdny. Začnite skenovať.</td></tr>
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
};

export default InventoryTab;

import React, { useMemo, useState, useEffect } from 'react';
import { Task, SystemBreak } from '../App';
import { useLanguage } from './LanguageContext';

declare var XLSX: any;

interface AnalyticsTabProps {
  tasks: Task[];
  onFetchArchivedTasks: () => Promise<Task[]>;
  systemBreaks: SystemBreak[];
}

type FilterMode = 'ALL' | 'TODAY' | 'YESTERDAY' | 'WEEK' | 'MONTH' | 'CUSTOM';

const DownloadIcon: React.FC<{ className?: string }> = ({ className }) => (
  <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
  </svg>
);

const AnalyticsTab: React.FC<AnalyticsTabProps> = ({ tasks: liveTasks, onFetchArchivedTasks, systemBreaks }) => {
  const [filterMode, setFilterMode] = useState<FilterMode>('ALL');
  const [customStart, setCustomStart] = useState('');
  const [customEnd, setCustomEnd] = useState('');

  const [includeArchive, setIncludeArchive] = useState(false);
  const [archivedTasks, setArchivedTasks] = useState<Task[]>([]);
  const [isLoadingArchive, setIsLoadingArchive] = useState(false);
  const { t, language } = useLanguage();

  const tasks = useMemo(() => {
      return includeArchive ? [...liveTasks, ...archivedTasks] : liveTasks;
  }, [liveTasks, archivedTasks, includeArchive]);

  useEffect(() => {
      if (includeArchive && archivedTasks.length === 0) {
          const load = async () => {
              setIsLoadingArchive(true);
              const data = await onFetchArchivedTasks();
              setArchivedTasks(data);
              setIsLoadingArchive(false);
          };
          load();
      } else if (!includeArchive && archivedTasks.length > 0) {
        setArchivedTasks([]);
      }
  }, [includeArchive]);

  const filteredTasks = useMemo(() => {
    if (filterMode === 'ALL') return tasks;

    const now = new Date();
    const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate());

    return tasks.filter(task => {
        if (!task.createdAt) return false;

        const taskDate = new Date(task.createdAt);
        const taskDayStart = new Date(taskDate.getFullYear(), taskDate.getMonth(), taskDate.getDate());

        switch(filterMode) {
            case 'TODAY':
                return taskDayStart.getTime() === todayStart.getTime();

            case 'YESTERDAY':
                const yesterdayStart = new Date(todayStart);
                yesterdayStart.setDate(yesterdayStart.getDate() - 1);
                return taskDayStart.getTime() === yesterdayStart.getTime();

            case 'WEEK':
                const weekAgo = todayStart.getTime() - (7 * 86400000);
                return taskDate.getTime() >= weekAgo;

            case 'MONTH':
                return taskDate.getMonth() === now.getMonth() && taskDate.getFullYear() === now.getFullYear();

            case 'CUSTOM':
                if (!customStart) return true;
                const start = new Date(customStart).setHours(0,0,0,0);
                const end = customEnd ? new Date(customEnd).setHours(23,59,59,999) : Infinity;
                return taskDate.getTime() >= start && taskDate.getTime() <= end;

            default:
                return true;
        }
    });
  }, [tasks, filterMode, customStart, customEnd]);

  const formatDuration = (ms: number) => {
    if (ms <= 0) return '-';
    const minutes = Math.round(ms / 60000);
    if (minutes < 1) return '< 1 min';
    if (minutes > 60) {
        const h = Math.floor(minutes / 60);
        const m = minutes % 60;
        return `${h}h ${m}m`;
    }
    return `${minutes} min`;
  };

  const calculateBlockedTime = (history: any[] | undefined, startTime: number, endTime: number): number => {
      let totalBlocked = 0;
      if (history && history.length > 0) {
          history.forEach(session => {
              const blockStart = session.start;
              const blockEnd = session.end || endTime;
              const overlapStart = Math.max(startTime, blockStart);
              const overlapEnd = Math.min(endTime, blockEnd);
              if (overlapEnd > overlapStart) totalBlocked += (overlapEnd - overlapStart);
          });
      }
      if (systemBreaks && systemBreaks.length > 0) {
          systemBreaks.forEach(br => {
              const breakStart = br.start;
              const breakEnd = br.end || endTime;
              const overlapStart = Math.max(startTime, breakStart);
              const overlapEnd = Math.min(endTime, breakEnd);
              if (overlapEnd > overlapStart) totalBlocked += (overlapEnd - overlapStart);
          });
      }
      return totalBlocked;
  };

  const stats = useMemo(() => {
    const workplaceCounts: Record<string, number> = {};
    const partCounts: Record<string, number> = {};
    const logisticsRefCounts: Record<string, number> = {}; 
    const logisticsOpCounts: Record<string, number> = {}; 

    let totalReactionTime = 0;
    let countReactionTime = 0;
    let totalLeadTime = 0;
    let countLeadTime = 0;
    let grandTotalExecutionTime = 0;

    const workerStatsMap: Record<string, any> = {};

    // --- INTEGRÁCIA LOKÁLNYCH LOGOV (ZERO FIREBASE) ---
    const rawLocalLogs = localStorage.getItem('inventory_work_logs');
    const localLogs = rawLocalLogs ? JSON.parse(rawLocalLogs) : [];

    const performanceTasks = filteredTasks.filter(t => t.status !== 'incorrectly_entered');
    const total = filteredTasks.length;
    const incorrectlyEntered = filteredTasks.filter(t => t.status === 'incorrectly_entered').length;
    const done = performanceTasks.filter(t => t.isDone).length;
    const missing = performanceTasks.filter(t => t.isMissing).length;
    const urgent = performanceTasks.filter(t => t.priority === 'URGENT' && t.isDone).length;
    const efficiency = performanceTasks.length === 0 ? 0 : Math.round((done / performanceTasks.length) * 100);

    performanceTasks.forEach(task => {
        let part = task.partNumber;
        let wp = task.workplace;
        let weight = 1;

        if (task.quantityUnit === 'pallet' && task.quantity) {
             const qty = parseFloat(task.quantity.replace(',', '.'));
             if (!isNaN(qty) && qty > 0) weight = qty;
        }

        if (task.type === 'logistics') {
            const refLabel = (part && part !== '-') ? part : 'N/A';
            const opLabel = (wp && wp !== '-') ? wp : '';
            const compoundKey = opLabel ? `${refLabel} [${opLabel}]` : refLabel;
            logisticsRefCounts[compoundKey] = (logisticsRefCounts[compoundKey] || 0) + weight;
            if (wp && wp !== '-') logisticsOpCounts[wp] = (logisticsOpCounts[wp] || 0) + 1; 
        } else {
            if (part && part !== '-') partCounts[part] = (partCounts[part] || 0) + weight;
            if (wp && wp !== '-') workplaceCounts[wp] = (workplaceCounts[wp] || 0) + weight;
        }

        if (task.createdAt) {
            if (task.startedAt) {
                const reaction = task.startedAt - task.createdAt;
                if (reaction > 0) { totalReactionTime += reaction; countReactionTime++; }
            }
            if (task.isDone && task.completedAt) {
                 const lead = task.completedAt - task.createdAt;
                 if (lead > 0) { totalLeadTime += lead; countLeadTime++; }
            }
        }

        if (task.isDone && task.completedBy) {
            const worker = task.completedBy;
            if (!workerStatsMap[worker]) {
                workerStatsMap[worker] = { 
                    name: worker, count: 0, totalVolume: 0, totalLeadMs: 0, countLead: 0, 
                    totalReactionMs: 0, countReaction: 0, totalExecutionMs: 0, totalStandardMinutes: 0 
                };
            }
            const ws = workerStatsMap[worker];
            ws.count += 1; 
            ws.totalVolume += weight;
            if (task.standardTime) ws.totalStandardMinutes += task.standardTime;

            if (task.createdAt) {
                 if (task.completedAt) {
                     const lead = task.completedAt - task.createdAt;
                     if (lead > 0) { ws.totalLeadMs += lead; ws.countLead++; }
                 }
                 if (task.startedAt && task.completedAt) {
                     const reaction = task.startedAt - task.createdAt;
                     if (reaction > 0) { ws.totalReactionMs += reaction; ws.countReaction++; }
                     let execution = task.completedAt - task.startedAt;
                     const blockedTime = calculateBlockedTime(task.inventoryHistory, task.startedAt, task.completedAt);
                     execution -= blockedTime;
                     if (execution > 0) { ws.totalExecutionMs += execution; grandTotalExecutionTime += execution; }
                 }
            }
        }
    });

    // --- PRIPOČÍTANIE LOKÁLNYCH ČASOV Z INVENTÚRY ---
    const now = new Date();
    const todayStr = now.toISOString().slice(0, 10);
    const yesterday = new Date(now); yesterday.setDate(yesterday.getDate() - 1);
    const yesterdayStr = yesterday.toISOString().slice(0, 10);
    const weekAgo = new Date(now); weekAgo.setDate(weekAgo.getDate() - 7);

    localLogs.forEach((log: any) => {
        let isIncluded = false;
        const logDate = new Date(log.date);

        switch(filterMode) {
            case 'ALL': isIncluded = true; break;
            case 'TODAY': isIncluded = log.date === todayStr; break;
            case 'YESTERDAY': isIncluded = log.date === yesterdayStr; break;
            case 'WEEK': isIncluded = logDate >= weekAgo; break;
            case 'MONTH': isIncluded = logDate.getMonth() === now.getMonth() && logDate.getFullYear() === now.getFullYear(); break;
            case 'CUSTOM':
                if (customStart) {
                    const start = new Date(customStart).setHours(0,0,0,0);
                    const end = customEnd ? new Date(customEnd).setHours(23,59,59,999) : Infinity;
                    isIncluded = logDate.getTime() >= start && logDate.getTime() <= end;
                } else isIncluded = true;
                break;
        }

        if (isIncluded) {
            const worker = log.worker;
            if (!workerStatsMap[worker]) {
                workerStatsMap[worker] = { 
                    name: worker, count: 0, totalVolume: 0, totalLeadMs: 0, countLead: 0, 
                    totalReactionMs: 0, countReaction: 0, totalExecutionMs: 0, totalStandardMinutes: 0 
                };
            }
            workerStatsMap[worker].totalExecutionMs += log.durationMs;
            grandTotalExecutionTime += log.durationMs;
        }
    });

    const getTop = (record: Record<string, number>, limit: number) => {
        return Object.entries(record).sort(([, a], [, b]) => b - a).slice(0, limit);
    };

    return {
        total, done, missing, urgent, efficiency,
        avgReaction: countReactionTime > 0 ? totalReactionTime / countReactionTime : 0,
        avgLead: countLeadTime > 0 ? totalLeadTime / countLeadTime : 0,
        grandTotalExecutionTime,
        incorrectlyEntered,
        topWorkplaces: getTop(workplaceCounts, 5),
        topParts: getTop(partCounts, 5),
        topLogRefs: getTop(logisticsRefCounts, 10),
        logisticsOpCounts,
        workerStats: Object.values(workerStatsMap).sort((a, b) => b.count - a.count)
    };
  }, [filteredTasks, systemBreaks, filterMode, customStart, customEnd]);

  const handleExportReport = () => {
    if (typeof XLSX === 'undefined') return;
    const wb = XLSX.utils.book_new();
    const kpiData = [
        { Metrika: t('kpi_total'), Hodnota: stats.total },
        { Metrika: t('kpi_worked'), Hodnota: (stats.grandTotalExecutionTime / 3600000).toFixed(2) },
        { Metrika: t('kpi_lead'), Hodnota: (stats.avgLead / 60000).toFixed(2) },
        { Metrika: t('kpi_react'), Hodnota: (stats.avgReaction / 60000).toFixed(2) },
        { Metrika: t('kpi_effic'), Hodnota: stats.efficiency },
        { Metrika: t('kpi_urgent'), Hodnota: stats.urgent },
        { Metrika: t('kpi_missing'), Hodnota: stats.missing },
        { Metrika: t('kpi_incorrect'), Hodnota: stats.incorrectlyEntered },
    ];
    const wsKPI = XLSX.utils.json_to_sheet(kpiData);
    XLSX.utils.book_append_sheet(wb, wsKPI, "KPI");
    XLSX.writeFile(wb, `Report_Analytika_${new Date().toISOString().slice(0,10)}.xlsx`);
  };

  return (
    <div className="max-w-6xl mx-auto space-y-6 pb-8 animate-fade-in">
        <h1 className="text-center text-2xl sm:text-3xl font-bold text-teal-400 mb-2">{t('analytics_title')}</h1>
        <div className="flex flex-col sm:flex-row justify-end gap-3 mb-2">
            <label className="flex items-center cursor-pointer gap-2 bg-gray-900 p-2 rounded-lg border border-gray-700">
                <input type="checkbox" checked={includeArchive} onChange={() => setIncludeArchive(!includeArchive)} className="form-checkbox h-5 w-5 text-teal-500 rounded focus:ring-teal-500 bg-gray-700 border-gray-600"/>
                <span className="text-sm font-bold text-teal-400">{isLoadingArchive ? t('loading_hist') : t('include_archive')}</span>
            </label>
            <button onClick={handleExportReport} className="flex items-center gap-2 bg-green-700 hover:bg-green-600 text-white px-4 py-2 rounded-lg text-sm font-bold shadow-md transition-colors">
                <DownloadIcon className="w-5 h-5" />{t('download_report')}
            </button>
        </div>

        <div className="bg-gray-800 p-4 rounded-xl shadow-md border border-gray-700 flex flex-col md:flex-row items-center justify-between gap-4">
            <div className="flex flex-wrap gap-2 justify-center">
                {(['ALL', 'TODAY', 'YESTERDAY', 'WEEK', 'MONTH', 'CUSTOM'] as FilterMode[]).map(mode => (
                    <button key={mode} onClick={() => setFilterMode(mode)} className={`px-4 py-2 rounded text-sm font-bold transition-colors ${filterMode === mode ? 'bg-teal-600 text-white' : 'bg-gray-700 text-gray-300 hover:bg-gray-600'}`}>{t(`filter_${mode.toLowerCase()}` as any)}</button>
                ))}
            </div>
            {filterMode === 'CUSTOM' && (
                <div className="flex items-center gap-2 bg-gray-900 p-2 rounded-lg border border-gray-600">
                    <input type="date" value={customStart} onChange={(e) => setCustomStart(e.target.value)} className="bg-gray-800 text-white text-sm rounded px-2 py-1 border border-gray-600 focus:border-teal-500 outline-none"/>
                    <span className="text-gray-400">-</span>
                    <input type="date" value={customEnd} onChange={(e) => setCustomEnd(e.target.value)} className="bg-gray-800 text-white text-sm rounded px-2 py-1 border border-gray-600 focus:border-teal-500 outline-none"/>
                </div>
            )}
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
            <div className="bg-gray-700 p-4 rounded-xl shadow-lg border-l-4 border-blue-500">
                <p className="text-gray-400 text-sm font-bold uppercase">{t('kpi_total')}</p>
                <p className="text-3xl font-extrabold text-white mt-1">{stats.total}</p>
            </div>
            <div className="bg-gray-700 p-4 rounded-xl shadow-lg border-l-4 border-green-500">
                <p className="text-gray-400 text-sm font-bold uppercase">{t('kpi_worked')}</p>
                <p className="text-3xl font-extrabold text-green-400 mt-1">{formatDuration(stats.grandTotalExecutionTime)}</p>
            </div>
            <div className="bg-gray-700 p-4 rounded-xl shadow-lg border-l-4 border-purple-500">
                <p className="text-gray-400 text-sm font-bold uppercase">{t('kpi_lead')}</p>
                <p className="text-3xl font-extrabold text-purple-400 mt-1">{formatDuration(stats.avgLead)}</p>
            </div>
             <div className="bg-gray-700 p-4 rounded-xl shadow-lg border-l-4 border-yellow-500">
                <p className="text-gray-400 text-sm font-bold uppercase">{t('kpi_react')}</p>
                <p className="text-3xl font-extrabold text-yellow-400 mt-1">{formatDuration(stats.avgReaction)}</p>
            </div>
        </div>

        <div className="bg-gray-900 border border-gray-700 p-4 rounded-xl shadow-lg">
             <h3 className="text-lg font-bold text-white mb-4 border-b border-gray-700 pb-2">{t('table_title')}</h3>
             <div className="overflow-x-auto custom-scrollbar">
                <table className="w-full text-left border-collapse min-w-[600px]">
                    <thead>
                        <tr className="text-gray-400 text-sm border-b border-gray-700">
                            <th className="py-2 px-2">{t('th_rank')}</th>
                            <th className="py-2 px-2">{t('th_name')}</th>
                            <th className="py-2 px-2 text-right">{t('th_done')}</th>
                            <th className="py-2 px-2 text-right text-sky-400">{language === 'sk' ? 'Objem (pal/ks)' : 'Volume'}</th>
                            <th className="py-2 px-2 text-right text-green-400">{t('th_work_time')}</th>
                        </tr>
                    </thead>
                    <tbody className="text-sm">
                        {stats.workerStats.map((ws: any, idx: number) => (
                            <tr key={ws.name} className="border-b border-gray-800 hover:bg-gray-800 transition-colors">
                                <td className="py-3 px-2 text-gray-500 font-mono">{idx + 1}</td>
                                <td className="py-3 px-2 font-bold text-white">{ws.name}</td>
                                <td className="py-3 px-2 text-right text-teal-400 font-bold">{ws.count}</td>
                                <td className="py-3 px-2 text-right text-sky-400 font-bold font-mono">{Number(ws.totalVolume.toFixed(1))}</td>
                                <td className="py-3 px-2 text-right text-green-400 font-bold font-mono">{formatDuration(ws.totalExecutionMs)}</td>
                            </tr>
                        ))}
                    </tbody>
                </table>
             </div>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
            <div className="bg-gray-900 border border-gray-700 p-6 rounded-xl shadow-lg">
                <h3 className="text-lg font-bold text-white mb-4 border-b border-gray-700 pb-2">{t('chart_wp')}</h3>
                <div className="space-y-4">
                    {stats.topWorkplaces.map(([name, count], idx) => (
                        <div key={name} className="relative">
                            <div className="flex justify-between text-sm mb-1">
                                <span className="text-gray-300 font-mono">{idx + 1}. {name}</span>
                                <span className="text-teal-400 font-bold">{Number(count.toFixed(1))}</span>
                            </div>
                            <div className="w-full bg-gray-700 rounded-full h-2.5">
                                <div className="bg-teal-600 h-2.5 rounded-full" style={{ width: `${(count / (stats.topWorkplaces[0]?.[1] || 1)) * 100}%` }}></div>
                            </div>
                        </div>
                    ))}
                </div>
            </div>

            <div className="bg-gray-900 border border-gray-700 p-6 rounded-xl shadow-lg">
                <h3 className="text-lg font-bold text-white mb-4 border-b border-gray-700 pb-2">{t('chart_parts')}</h3>
                <div className="space-y-4">
                     {stats.topParts.map(([name, count], idx) => (
                        <div key={name} className="relative">
                            <div className="flex justify-between text-sm mb-1">
                                <span className="text-gray-300 font-mono">{idx + 1}. {name}</span>
                                <span className="text-blue-400 font-bold">{Number(count.toFixed(1))}</span>
                            </div>
                            <div className="w-full bg-gray-700 rounded-full h-2.5">
                                <div className="bg-blue-600 h-2.5 rounded-full" style={{ width: `${(count / (stats.topParts[0]?.[1] || 1)) * 100}%` }}></div>
                            </div>
                        </div>
                    ))}
                </div>
            </div>

            <div className="bg-gray-900 border border-gray-700 p-6 rounded-xl shadow-lg sm:col-span-2">
                <h3 className="text-lg font-bold text-sky-400 mb-4 border-b border-gray-700 pb-2">{t('chart_log_refs')}</h3>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-x-8 gap-y-4">
                     {stats.topLogRefs.map(([name, count], idx) => (
                        <div key={name} className="relative">
                            <div className="flex justify-between text-sm mb-1">
                                <span className="text-gray-300 font-mono">{idx + 1}. {name}</span>
                                <span className="text-sky-400 font-bold">{Number(count.toFixed(1))}</span>
                            </div>
                            <div className="w-full bg-gray-700 rounded-full h-2.5">
                                <div className="bg-sky-600 h-2.5 rounded-full" style={{ width: `${(count / (stats.topLogRefs[0]?.[1] || 1)) * 100}%` }}></div>
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        </div>
    </div>
  );
};

