        <path d="M20 8h-3V4H3v14h1v2a2 2 0 0 0 2 2 2 2 0 0 0 2-2v-2h8v2a2 2 0 0 0 2 2 2 2 0 0 0 2-2v-2h1V8zm-2 2v3h-3v-3h3zM5 18H4V6h11v12H5zm13 0h-1v-2h-3v-2h4v4z"/>
