const TaskList: React.FC<TaskListProps> = (props) => {
    const { t, language } = useLanguage();

    const [priorityEditId, setPriorityEditId] = useState<string | null>(null);
    const [missingId, setMissingId] = useState<string | null>(null);
    const [noteId, setNoteId] = useState<string | null>(null);
    const [noteVal, setNoteVal] = useState('');
    const [deleteId, setDeleteId] = useState<string | null>(null);
    const [copiedId, setCopiedId] = useState<string | null>(null);

    const openPriorityModal = (task: Task) => {
        setPriorityEditId(task.id);
        setMissingId(null); setNoteId(null); setDeleteId(null);
    };

    const confirmPriority = (id: string, newPriority: PriorityLevel) => {
        const task = props.tasks.find(t => t.id === id);
        if (task) props.onEditTask(id, task.text, newPriority);
        setPriorityEditId(null);
    };

    const handleMissingClick = (task: Task, e: React.MouseEvent) => {
        e.stopPropagation();
        if (task.isMissing) props.onToggleMissing(task.id);
        else {
            setMissingId(missingId === task.id ? null : task.id);
            setPriorityEditId(null); setNoteId(null); setDeleteId(null);
        }
    };

    const confirmMissing = (id: string, reason: string) => {
        props.onToggleMissing(id, reason);
        setMissingId(null);
    };

    const handleNoteClick = (task: Task) => {
        setNoteId(noteId === task.id ? null : task.id);
        setNoteVal(task.note || '');
        setPriorityEditId(null); setMissingId(null); setDeleteId(null);
    };

    const saveNote = (id: string) => {
        props.onAddNote(id, noteVal);
        setNoteId(null);
    };

    const handleDeleteClick = (id: string) => {
        setDeleteId(id);
        setPriorityEditId(null); setMissingId(null); setNoteId(null);
    };

    const confirmDelete = () => {
        if (deleteId) {
            props.onDeleteTask(deleteId);
            setDeleteId(null);
        }
    };

    const handleCopyPart = (id: string, text: string) => {
        if (!text) return;
        navigator.clipboard.writeText(text).then(() => {
            setCopiedId(id);
            setTimeout(() => setCopiedId(null), 1500);
        }).catch(err => console.error('Copy failed', err));
    };

    const renderFormattedText = (text: string | undefined) => {
        if (!text) return null;
        if (!text.includes(';')) return text;
        const parts = text.split(';');
        return parts.map((part, index) => (
            <React.Fragment key={index}>
                {part.trim()}
                {index < parts.length - 1 && (
                    <span className="mx-2 text-teal-400 font-bold opacity-80 inline-block transform translate-y-[1px]">➤</span>
                )}
            </React.Fragment>
        ));
    };

    const getUnitLabel = (count: number, unit: string) => {
        if (language === 'sk') {
            let key = count === 1 ? `unit_${unit}_1` : (count >= 2 && count <= 4 ? `unit_${unit}_2_4` : `unit_${unit}_5`);
            return t(key as any) || unit;
        } else {
            let key = count === 1 ? `unit_${unit}_1` : `unit_${unit}_5`; 
            return t(key as any) || unit;
        }
    };

    return (
        <div className="flex flex-col space-y-3 pb-20">
            {props.tasks.length === 0 && (
                <div className="text-center py-12 text-gray-500 italic bg-gray-800 rounded-xl border border-gray-700">{t('empty_tasks')}</div>
            )}

            {props.tasks.map((task) => {
                const isSearchingMode = task.isBlocked; 
                const isManualBlocked = task.isManualBlocked;
                const isUrgent = task.priority === 'URGENT' && !task.isDone;
                // --- DETEKCIA ŠPECIÁLNEJ ÚLOHY ---
                const isSystemInventoryTask = task.partNumber === "Počítanie zásob";

                // --- FILTER VIDITEĽNOSTI INVENTÚRY ---
                if (isSystemInventoryTask && !props.hasPermission('perm_tab_inventory')) {
                    return null;
                }

                let bgClass = "";
                let borderClass = "";
                let textClass = "text-white";

                if (task.isDone) {
                    bgClass = "bg-gray-800 opacity-60";
                    textClass = "text-gray-500 line-through";
                } else {
                    if (isManualBlocked) { bgClass = "bg-black"; textClass = "text-gray-500"; borderClass = "border-l-4 border-gray-800"; }
                    else if (isSearchingMode) { bgClass = "bg-gray-800"; borderClass = "border-l-4 border-gray-600"; }
                    else if (isSystemInventoryTask) { bgClass = "bg-[#4169E1]/20"; borderClass = "border-l-4 border-[#4169E1]"; }
                    else if (task.isInProgress) { bgClass = "bg-[#FFD700]/20"; borderClass = "border-l-4 border-[#FFD700]"; }
                    else if (task.isMissing) { bgClass = "bg-red-900/20"; borderClass = "border-l-4 border-red-500"; }
                    else if (task.type === 'logistics') { bgClass = "bg-sky-900/10"; borderClass = "border-l-4 border-sky-500"; }
                    else {
                        switch (task.priority) {
                            case 'URGENT': bgClass = "bg-[#FF8C00]/20"; borderClass = "border-l-4 border-[#FF8C00]"; break;
                            case 'LOW': bgClass = "bg-[#1E90FF]/20"; borderClass = "border-l-4 border-[#1E90FF]"; break;
                            case 'NORMAL':
                            default: bgClass = "bg-[#8A2BE2]/20"; borderClass = "border-l-4 border-[#8A2BE2]"; break;
                        }
                    }
                }

                const qtyNum = parseFloat(task.quantity || '0');
                const unitLabel = task.quantityUnit ? getUnitLabel(qtyNum, task.quantityUnit) : '';

                return (
                    <div key={task.id} className={`group relative flex flex-col sm:flex-row rounded-lg shadow-md overflow-hidden transition-all duration-200 items-stretch ${bgClass} ${borderClass} ${!task.isDone ? 'hover:shadow-lg' : ''}`}>
                        {isUrgent && !isManualBlocked && <div className="absolute left-0 top-0 bottom-0 w-1 bg-[#FF8C00] animate-pulse z-50"></div>}

                        {/* VODOZNAK LUPY NA POZADÍ (Iba pri hľadaní tovaru) */}
                        {isSearchingMode && !task.isDone && (
                            <div className="absolute right-20 top-1/2 -translate-y-1/2 pointer-events-none opacity-10">
                                <SearchIcon className="w-32 h-32 text-gray-400" />
                            </div>
                        )}

                        {/* VODOZNAK VÝSTRAŽNÉHO TROJUHOLNÍKA NA POZADÍ (Iba pri urgentnej úlohe) */}
                        {isUrgent && !isManualBlocked && !task.isDone && (
                            <div className="absolute left-4 top-1/2 -translate-y-1/2 pointer-events-none opacity-10">
                                <ExclamationIcon className="w-32 h-32 text-red-500" />
                            </div>
                        )}

                        <div className="flex-grow p-4 flex flex-col gap-1 min-w-0 relative">
                            {isSystemInventoryTask && !task.isDone && (
                                <div className="absolute left-0 top-0 p-1">
                                    <span className="bg-[#4169E1] text-white text-[10px] font-bold uppercase tracking-widest px-1 rounded border border-[#4169E1]">INVENTÚRA</span>
                                </div>
                            )}
                            <div className="relative z-10">
                                {/* PULZUJÚCI ŠTÍTOK PRE URGENTNÉ ÚLOHY (ORANŽOVÝ) */}
                                {isUrgent && !isManualBlocked && (
                                    <div className="mb-1">
                                        <span className="bg-orange-600 text-white text-[10px] font-black uppercase tracking-widest px-2 py-0.5 rounded animate-pulse border border-orange-500 shadow-[0_0_10px_rgba(234,88,12,0.4)] inline-block">
                                            🔥 {t('status_urgent')}
                                        </span>
                                    </div>
                                )}

                                {/* PULZUJÚCI ŠTÍTOK PRE HĽADANIE TOVARU (SIVÝ) */}
                                {isSearchingMode && !task.isDone && (
                                    <div className="mb-1">
                                        <span className="bg-gray-500 text-white text-[10px] font-black uppercase tracking-widest px-2 py-0.5 rounded animate-pulse border border-gray-400 shadow-sm inline-block">
                                            🔍 {t('status_inventory')}
                                        </span>
                                    </div>
                                )}

                                {/* PULZUJÚCI DÔVOD CHÝBAJÚCEHO TOVARU */}
                                {task.isMissing && !task.isDone && task.missingReason && (
                                    <div className="mb-1">
                                        <span className="bg-red-600 text-white text-[10px] font-black uppercase tracking-widest px-2 py-0.5 rounded animate-pulse border border-red-500 shadow-sm inline-block">
                                            ⚠️ {task.missingReason}
                                        </span>
                                    </div>
                                )}

                                <div className="flex justify-between items-start gap-3">
                                    <h3 className={`text-2xl sm:text-3xl font-bold truncate leading-tight ${textClass}`}>{renderFormattedText(task.partNumber || task.text)}</h3>
                                    <div className="flex flex-col items-end flex-shrink-0">
                                        <span className={`bg-black border border-gray-700 shadow-inner px-3 py-1 rounded-full text-xl font-bold ${textClass}`}>{task.quantity || "-"} <span className="ml-1 text-lg font-normal">{unitLabel}</span></span>
                                        <div className="text-xs text-gray-400 mt-1 font-mono text-right"><span className="font-bold text-gray-500">{task.createdBy}</span> • {new Date(task.createdAt || 0).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</div>
                                    </div>
                                </div>
                                <div className="flex flex-wrap gap-2 items-center">
                                    <span className={`text-lg font-bold uppercase tracking-wider ${task.isDone ? 'text-gray-600' : isManualBlocked ? 'text-gray-600' : 'text-cyan-400'}`}>{task.workplace || "---"}</span>
                                    {task.note && <span className="inline-block px-2 py-0.5 rounded bg-[#fef9c3] text-gray-800 text-xs font-bold shadow-sm border border-yellow-200 leading-tight">{task.note}</span>}
                                </div>
                                {task.isInProgress && (
                                    <div className="flex"><span className="text-[#FFD700] text-xs font-bold uppercase tracking-wide border border-[#FFD700]/50 bg-[#FFD700]/10 px-2 py-0.5 rounded animate-pulse">{t('status_resolving')} {task.inProgressBy}</span></div>
                                )}

                                {/* INFO O DOKONČENÍ */}
                                {task.isDone && task.completedBy && (
                                    <div className="mt-2 flex items-center gap-1.5 border-t border-gray-700/50 pt-1.5 animate-fade-in">
                                        <div className="w-1.5 h-1.5 rounded-full bg-green-500 shadow-[0_0_5px_rgba(34,197,94,0.5)]"></div>
                                        <span className="text-[10px] font-bold uppercase text-green-500/80 tracking-wide">
                                            {t('task_completed_label')}: <span className="text-green-400">{task.completedBy}</span> {t('at_time')} <span className="font-mono">{new Date(task.completedAt || 0).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</span>
                                        </span>
                                    </div>
                                )}
                            </div>
                        </div>

                        {/* RIGHT COLUMN: Action Buttons */}
                        <div className="flex flex-shrink-0 items-center justify-center p-3 z-10">
                            <div className="grid grid-cols-5 gap-2 items-center justify-center">
                                {isSystemInventoryTask ? (
                                    // Špeciálne tlačidlá pre Inventúru (iba Vymazať)
                                    props.hasPermission('perm_btn_delete') && (
                                        <button onClick={() => handleDeleteClick(task.id)} className="w-16 h-16 flex items-center justify-center rounded-lg bg-red-900/50 text-red-500 hover:bg-red-800 hover:text-white border border-red-800 transition-colors">
                                            <TrashIcon className="w-8 h-8" />
                                        </button>
                                    )
                                ) : !task.isDone ? (
                                    // Štandardné tlačidlá pre aktívne úlohy
                                    <>
                                        {!isSearchingMode && !isManualBlocked && props.hasPermission('perm_btn_resolve') && (
                                            <button onClick={() => props.onSetInProgress(task.id)} className={`w-16 h-16 flex items-center justify-center rounded-xl transition-all active:scale-95 shadow-lg ${task.isInProgress ? 'bg-yellow-600 text-white border border-yellow-500' : 'bg-gray-700 text-yellow-500 hover:bg-gray-600 border border-gray-600'}`}>
                                                {task.isInProgress ? <PauseIcon className="w-10 h-10" /> : <PlayIcon className="w-10 h-10" />}
                                            </button>
                                        )}
                                        {!isManualBlocked && props.hasPermission('perm_btn_copy') && (
                                            <button onClick={() => (task.isInProgress || isSearchingMode) && handleCopyPart(task.id, task.partNumber || '')} disabled={!task.isInProgress && !isSearchingMode} className={`w-16 h-16 flex items-center justify-center rounded-lg transition-all shadow-lg border ${(!task.isInProgress && !isSearchingMode) ? 'bg-gray-700 text-gray-500 border-gray-600 cursor-not-allowed opacity-50' : (copiedId === task.id ? 'bg-green-600 border-green-500 text-white' : 'bg-blue-600 border-blue-500 text-white hover:bg-blue-500 active:scale-95')}`}>
                                                {copiedId === task.id ? <span className="font-bold text-xs">OK</span> : <CopyIcon className="w-8 h-8" />}
                                            </button>
                                        )}
                                        {!isManualBlocked && props.hasPermission('perm_btn_missing') && (
                                            <button onClick={(e) => (task.isInProgress || isSearchingMode) && handleMissingClick(task, e)} disabled={!task.isInProgress && !isSearchingMode} className={`w-16 h-16 flex items-center justify-center rounded-xl transition-all shadow-lg border ${(!task.isInProgress && !isSearchingMode) ? 'bg-gray-700 text-gray-500 border-gray-600 cursor-not-allowed opacity-50' : (task.isMissing ? 'bg-red-800 text-white border-red-500' : 'bg-red-600 text-white hover:bg-red-50 border-red-500 active:scale-95')}`}>
                                                <ExclamationIcon className="w-10 h-10" />
                                            </button>
                                        )}
                                        {!isManualBlocked && props.hasPermission('perm_btn_lock') && (
                                            <button onClick={() => props.onToggleBlock(task.id)} title={t('perm_btn_lock')} className={`w-16 h-16 flex items-center justify-center rounded-lg transition-all active:scale-95 shadow-lg ${task.isBlocked ? 'bg-gray-600 text-white border border-gray-500' : 'bg-gray-700 text-gray-400 hover:bg-gray-600 border border-gray-600'}`}><SearchIcon className="w-8 h-8" /></button>
                                        )}
                                        {props.hasPermission('perm_btn_block_new') && (
                                            <button onClick={() => props.onToggleManualBlock(task.id)} className={`w-16 h-16 flex items-center justify-center rounded-lg border shadow-lg transition-all active:scale-95 ${task.isManualBlocked ? 'bg-[#4169E1] border-[#4169E1] text-white' : 'bg-black border-[#4169E1] text-[#4169E1]'}`}><LockIcon className="w-8 h-8" /></button>
                                        )}
                                        {!isSearchingMode && !isManualBlocked && props.hasPermission('perm_btn_finish') && (
                                            <button onClick={() => task.isInProgress && props.onToggleTask(task.id)} disabled={!task.isInProgress} className={`w-16 h-16 flex items-center justify-center rounded-xl transition-all shadow-xl border ${task.isInProgress ? 'bg-lime-600 text-white hover:bg-lime-500 active:scale-95 border-lime-500' : 'bg-gray-700 text-gray-500 border-gray-600 cursor-not-allowed opacity-50'}`}><CheckIcon className="w-12 h-12" /></button>
                                        )}
                                        {!isSearchingMode && !isManualBlocked && props.hasPermission('perm_btn_edit') && (
                                            <button onClick={() => openPriorityModal(task)} className="w-16 h-16 flex items-center justify-center rounded-lg bg-gray-700 text-blue-400 border border-gray-600 hover:bg-gray-600 hover:text-white transition-colors"><SignalIcon className="w-8 h-8" /></button>
                                        )}
                                        {!isSearchingMode && !isManualBlocked && props.hasPermission('perm_btn_note') && (
                                            <button onClick={() => handleNoteClick(task)} className={`w-16 h-16 flex items-center justify-center rounded-lg border transition-colors ${task.note ? 'bg-[#fef9c3] text-gray-800 border-yellow-200' : 'bg-gray-700 text-gray-300 border-gray-600 hover:bg-gray-600'}`}><ChatIcon className="w-8 h-8" /></button>
                                        )}
                                        {props.hasPermission('perm_btn_delete') && (
                                            <button onClick={() => handleDeleteClick(task.id)} className="w-16 h-16 flex items-center justify-center rounded-lg bg-red-900/50 text-red-500 hover:bg-red-800 hover:text-white border border-red-800 transition-colors"><TrashIcon className="w-8 h-8" /></button>
                                        )}
                                        {!isSearchingMode && !isManualBlocked && props.hasPermission('perm_btn_incorrect') && (
                                            <button 
                                                onClick={() => props.onMarkAsIncorrect(task.id)} 
                                                className="w-16 h-16 flex items-center justify-center rounded-xl transition-all shadow-lg border bg-white border-red-600 text-red-600 hover:bg-red-50 active:scale-95"
                                            >
                                                <BanIcon className="w-10 h-10" />
                                            </button>
                                        )}
                                    </>
                                ) : (
                                    // Štandardné tlačidlá pre dokončené úlohy
                                    <>
                                        {props.hasPermission('perm_btn_copy') && (
                                            <button onClick={() => handleCopyPart(task.id, task.partNumber || '')} className={`w-16 h-16 flex items-center justify-center rounded-xl transition-all active:scale-95 shadow-lg border ${copiedId === task.id ? 'bg-green-600 border-green-500 text-white' : 'bg-blue-600 border-blue-500 text-white hover:bg-blue-500'}`}><CopyIcon className="w-8 h-8" /></button>
                                        )}
                                        {props.hasPermission('perm_btn_return') && (
                                            <button onClick={() => props.onToggleTask(task.id)} className="w-16 h-16 flex items-center justify-center rounded-xl bg-orange-600 hover:bg-orange-500 text-white shadow-md transition-all active:scale-95 border border-orange-500"><ReturnIcon className="w-10 h-10" /></button>
                                        )}
                                        {props.hasPermission('perm_btn_delete') && (
                                            <button onClick={() => handleDeleteClick(task.id)} className="w-16 h-16 flex items-center justify-center rounded-lg bg-red-900/50 text-red-500 hover:bg-red-800 hover:text-white border border-red-800 transition-colors"><TrashIcon className="w-8 h-8" /></button>
                                        )}
                                    </>
                                )}
                            </div>
                        </div>
                    </div>
                );
            })}

            {/* Modals Portals (Priority, Missing, Note, Delete) */}
            {priorityEditId && createPortal(<div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in" onClick={() => setPriorityEditId(null)}><div className="bg-gray-800 border-2 border-blue-500 rounded-xl shadow-2xl w-full max-w-md p-6 relative" onClick={e => e.stopPropagation()}><h3 className="text-xl font-bold text-blue-400 mb-6 text-center uppercase tracking-wide">{t('priority_label')}</h3><div className="grid grid-cols-1 gap-3"><button onClick={() => confirmPriority(priorityEditId, 'LOW')} className="p-4 bg-slate-700 hover:bg-slate-600 border border-slate-500 text-white rounded-lg font-bold transition-all duration-200 text-lg shadow-md hover:translate-x-1 uppercase">{t('prio_low')}</button><button onClick={() => confirmPriority(priorityEditId, 'NORMAL')} className="p-4 bg-green-700 hover:bg-green-600 border border-green-500 text-white rounded-lg font-bold transition-all duration-200 text-lg shadow-md hover:translate-x-1 uppercase">{t('prio_normal')}</button><button onClick={() => confirmPriority(priorityEditId, 'URGENT')} className="p-4 bg-red-700 hover:bg-red-600 border border-red-500 text-white rounded-lg font-bold transition-all duration-200 text-lg shadow-md hover:translate-x-1 uppercase">{t('prio_urgent')}</button></div><button onClick={() => setPriorityEditId(null)} className="w-full mt-6 py-4 bg-gray-700 text-gray-300 rounded-lg hover:bg-gray-600 font-bold transition-colors">{t('btn_cancel')}</button></div></div>, document.body)}
            {missingId && createPortal(<div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in" onClick={() => setMissingId(null)}><div className="bg-gray-800 border-2 border-red-600 rounded-xl shadow-2xl w-full max-w-md p-6 relative" onClick={e => e.stopPropagation()}><h3 className="text-xl font-bold text-red-400 mb-6 text-center uppercase tracking-wide">{t('modal_missing_title')}</h3><div className="grid grid-cols-1 gap-3">{props.missingReasons.map(r => (<button key={r.id} onClick={() => confirmMissing(missingId, r.value)} className="p-4 bg-gray-700 hover:bg-red-900/30 border border-gray-600 hover:border-red-500 text-white rounded-lg font-bold transition-all duration-200 text-lg shadow-md hover:translate-x-1">{r.value}</button>))}</div><button onClick={() => setMissingId(null)} className="w-full mt-6 py-4 bg-gray-700 text-gray-300 rounded-lg hover:bg-gray-600 font-bold transition-colors">{t('btn_cancel')}</button></div></div>, document.body)}
            {noteId && createPortal(<div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in" onClick={() => setNoteId(null)}><div className="bg-gray-800 border-2 border-yellow-500 rounded-xl shadow-2xl w-full max-w-md p-6 relative" onClick={e => e.stopPropagation()}><h3 className="text-xl font-bold text-yellow-400 mb-4 text-center uppercase tracking-wide">{t('btn_note')}</h3><textarea value={noteVal} onChange={(e) => setNoteVal(e.target.value)} className="w-full bg-gray-700 text-white p-3 rounded-lg border border-gray-600 focus:border-yellow-500 outline-none mb-4" rows={4} autoFocus placeholder={t('btn_note') + "..."} /><div className="flex gap-3"><button onClick={() => saveNote(noteId)} className="flex-1 py-3 bg-yellow-600 hover:bg-yellow-500 text-white rounded-lg font-bold transition-colors">{t('btn_save')}</button><button onClick={() => setNoteId(null)} className="flex-1 py-3 bg-gray-700 hover:bg-gray-600 text-gray-300 rounded-lg font-bold transition-colors">{t('btn_cancel')}</button></div></div></div>, document.body)}
            {deleteId && createPortal(<div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in" onClick={() => setDeleteId(null)}><div className="bg-gray-800 border-2 border-red-600 rounded-xl shadow-2xl w-full max-w-md p-6 relative" onClick={e => e.stopPropagation()}><div className="text-center mb-6"><div className="w-16 h-16 bg-red-900/30 rounded-full flex items-center justify-center mx-auto mb-4 border border-red-500/50"><TrashIcon className="w-8 h-8 text-red-500" /></div><h3 className="text-xl font-bold text-white mb-2">{t('miss_delete_confirm')}</h3></div><div className="flex gap-3"><button onClick={() => setDeleteId(null)} className="flex-1 py-3 bg-gray-700 text-gray-300 rounded-lg hover:bg-gray-600 font-bold transition-colors">{t('btn_cancel')}</button><button onClick={confirmDelete} className="flex-1 py-3 bg-red-600 text-white rounded-lg hover:bg-red-700 font-bold transition-colors shadow-lg flex items-center justify-center gap-2"><TrashIcon className="w-5 h-5" />Vymazať</button></div></div></div>, document.body)}
        </div>
    );
};

export default TaskList;

import React, { useState, useEffect, useRef } from 'react';
import LoginScreen from './components/LoginScreen';
import PartSearchScreen from './components/PartSearchScreen';
import { db } from './firebase';
import { 
  collection, 
  onSnapshot, 
  addDoc, 
  updateDoc, 
  deleteDoc, 
  doc, 
  query, 
  orderBy,
  writeBatch,
  getDocs,
  getDoc,
  where,
  limit,
  setDoc,
  increment // Added increment
} from 'firebase/firestore';
import { partNumbers as initialParts, workplaces as initialWorkplaces, initialMissingReasons as seedMissingReasons } from './data/mockParts';

export interface UserData {
  id?: string;
  username: string;
  password: string;
  role: 'ADMIN' | 'USER' | 'LEADER';
}

export interface DBItem {
  id: string;
  value: string;
  standardTime?: number;
  description?: string;
}

export type PriorityLevel = 'LOW' | 'NORMAL' | 'URGENT';

export interface InventorySession {
    start: number;
    end?: number;
}

export interface Task {
  id: string; 
  text: string;
  partNumber?: string;
  workplace?: string;
  quantity?: string;
  quantityUnit?: string;
  standardTime?: number;
  isDone: boolean;
  priority?: PriorityLevel; 
  completionTime?: string;
  completedBy?: string | null;
  status?: 'completed' | 'incorrectly_entered';
  isMissing?: boolean;
  missingReportedBy?: string | null;
  missingReason?: string;
  isInProgress?: boolean;
  inProgressBy?: string | null;
  createdAt?: number; 
  createdBy?: string;
  startedAt?: number; 
  completedAt?: number; 
  note?: string;
  isBlocked?: boolean; // For Inventory
  isManualBlocked?: boolean; // For new manual block feature
  inventoryHistory?: InventorySession[];
  type?: 'production' | 'logistics'; 
}

export interface Notification {
    id: string;
    partNumber: string;
    reason: string;
    reportedBy: string;
    timestamp: number;
}

export interface PartRequest {
    id: string;
    partNumber: string;
    requestedBy: string;
    requestedAt: number;
}

export interface BreakSchedule {
    id: string;
    start: string;
    end: string;
}

export interface SystemBreak {
    id: string;
    start: number;
    end?: number;
    isActive: boolean;
}

export interface BOMItem {
    id: string;
    parentPart: string;
    childPart: string;
    quantity: number;
}

export interface BOMRequest {
    id: string;
    parentPart: string;
    requestedBy: string;
    requestedAt: number;
}

export interface Role {
    id: string;
    name: string;
    isSystem?: boolean;
}

export interface Permission {
    id: string;
    roleId: string;
    permissionName: string;
}

export interface SystemConfig {
    maintenanceMode: boolean;
    maintenanceStart?: string;
    maintenanceEnd?: string;
    allowedIPs: string[];
    ipCheckEnabled: boolean;
}

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(false);
  const [currentUser, setCurrentUser] = useState<string>('');
  const [currentUserRole, setCurrentUserRole] = useState<'ADMIN' | 'USER' | 'LEADER'>('USER');
  const [tasks, setTasks] = useState<Task[]>([]);

  // Data
  const [users, setUsers] = useState<UserData[]>([]);
  const [parts, setParts] = useState<DBItem[]>([]);
  const [workplaces, setWorkplaces] = useState<DBItem[]>([]);
  const [missingReasons, setMissingReasons] = useState<DBItem[]>([]);
  const [logisticsOperations, setLogisticsOperations] = useState<DBItem[]>([]); // New state
  const [partRequests, setPartRequests] = useState<PartRequest[]>([]);
  const [breakSchedules, setBreakSchedules] = useState<BreakSchedule[]>([]);
  const [systemBreaks, setSystemBreaks] = useState<SystemBreak[]>([]);
  const [isBreakActive, setIsBreakActive] = useState(false);
  const [bomItems, setBomItems] = useState<BOMItem[]>([]);
  const [bomRequests, setBomRequests] = useState<BOMRequest[]>([]);
  const [roles, setRoles] = useState<Role[]>([]);
  const [permissions, setPermissions] = useState<Permission[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);

  // System Config (Maintenance & IP)
  const [systemConfig, setSystemConfig] = useState<SystemConfig>({
      maintenanceMode: false,
      allowedIPs: [],
      ipCheckEnabled: false
  });

  // Performance Monitoring
  const [dbLoadWarning, setDbLoadWarning] = useState<boolean>(false);

  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);

  // Sound logic refs to avoid re-subscribing listeners
  const isFirstLoad = useRef(true);
  const rolesRef = useRef<Role[]>([]);
  const permissionsRef = useRef<Permission[]>([]);
  const currentUserRoleRef = useRef(currentUserRole);

  // Sync refs
  useEffect(() => { rolesRef.current = roles; }, [roles]);
  useEffect(() => { permissionsRef.current = permissions; }, [permissions]);
  useEffect(() => { currentUserRoleRef.current = currentUserRole; }, [currentUserRole]);

  // Helper function using refs for use inside listeners
  const checkPermissionRef = (permName: string) => {
      const currentRole = currentUserRoleRef.current;
      if (currentRole === 'ADMIN' && (permName === 'perm_tab_permissions' || permName === 'perm_manage_roles' || permName === 'perm_tab_settings')) {
          return true;
      }
      const r = rolesRef.current.find(r => r.name === currentRole);
      if (!r) return false;
      return permissionsRef.current.some(p => p.roleId === r.id && p.permissionName === permName);
  };

  // --- INITIALIZATION ---

  useEffect(() => {
    const storedUser = localStorage.getItem('app_user');
    const storedRole = localStorage.getItem('app_role');
    if (storedUser && storedRole) {
      setCurrentUser(storedUser);
      setCurrentUserRole(storedRole as any);
      setIsAuthenticated(true);
    }
  }, []);

  useEffect(() => {
    const handler = (e: any) => {
      e.preventDefault();
      setDeferredPrompt(e);
    };
    window.addEventListener('beforeinstallprompt', handler);
    return () => window.removeEventListener('beforeinstallprompt', handler);
  }, []);

  const handleInstallApp = async () => {
    if (!deferredPrompt) return;
    deferredPrompt.prompt();
    const { outcome } = await deferredPrompt.userChoice;
    setDeferredPrompt(null);
  };

  const hasPermission = (permName: string) => {
      if (currentUserRole === 'ADMIN' && (permName === 'perm_tab_permissions' || permName === 'perm_manage_roles' || permName === 'perm_tab_settings')) {
          return true;
      }
      const r = roles.find(r => r.name === currentUserRole);
      if (!r) return false;
      return permissions.some(p => p.roleId === r.id && p.permissionName === permName);
  };

  const handleLogout = () => { setIsAuthenticated(false); setCurrentUser(''); setCurrentUserRole('USER'); localStorage.removeItem('app_user'); localStorage.removeItem('app_role'); };

  // --- DATA FETCHING ---

  // System Config Listener
  useEffect(() => {
      const configRef = doc(db, 'system_data', 'config');
      return onSnapshot(configRef, (docSnap) => {
          if (docSnap.exists()) {
              setSystemConfig(docSnap.data() as SystemConfig);
          } else {
              // Set defaults if document doesn't exist
              setDoc(configRef, { maintenanceMode: false, allowedIPs: [], ipCheckEnabled: false });
          }
      });
  }, []);

  // Enforce Maintenance Mode & IP Checks
  useEffect(() => {
      if (isAuthenticated && currentUserRole !== 'ADMIN') {
          const now = new Date();
          const currentISO = new Date(now.getTime() - (now.getTimezoneOffset() * 60000)).toISOString().slice(0, 16);

          const isScheduledMaintenance = systemConfig.maintenanceStart && systemConfig.maintenanceEnd && 
                                         currentISO >= systemConfig.maintenanceStart && 
                                         currentISO <= systemConfig.maintenanceEnd;

          if (systemConfig.maintenanceMode || isScheduledMaintenance) {
              console.log('Force logging out due to maintenance mode.');
              handleLogout();
              alert('Systém prešiel do servisného módu. Boli ste odhlásení.');
          }
      }
  }, [systemConfig, isAuthenticated, currentUserRole]);

  // Tasks - Realtime
  useEffect(() => {
    const q = query(collection(db, 'tasks')); 

    return onSnapshot(q, (snapshot) => {
      const newTasks = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Task));

      if (newTasks.length > 500) {
          setDbLoadWarning(true);
      } else {
          setDbLoadWarning(false);
      }

      if (!isFirstLoad.current) {
          snapshot.docChanges().forEach((change) => {
              if (change.type === 'added') {
                  const task = change.doc.data() as Task;
                  if (task.createdAt && (Date.now() - task.createdAt < 10000)) {
                      if (checkPermissionRef('perm_play_sound')) {
                          try {
                              const audio = new Audio('https://codeskulptor-demos.commondatastorage.googleapis.com/pang/pop.mp3');
                              audio.play().catch(e => console.log('Sound blocked', e));
                          } catch (e) {}
                      }
                  }
              }
          });
      }
      isFirstLoad.current = false;

      // Sort Logic
      const priorityOrder: Record<string, number> = { 'URGENT': 0, 'NORMAL': 1, 'LOW': 2 };
      const sortedTasks = newTasks.sort((a, b) => {
        if (a.isDone !== b.isDone) return a.isDone ? 1 : -1;
        if (a.isDone) {
            const timeA = a.completedAt || a.createdAt || 0;
            const timeB = b.completedAt || b.createdAt || 0;
            return timeB - timeA; 
        }

        // --- ACTIVE TASKS SORTING ---

        // Manual Blocked tasks should be at the absolute bottom of the active list
        const aManBlocked = a.isManualBlocked ? 1 : 0;
        const bManBlocked = b.isManualBlocked ? 1 : 0;
        if (aManBlocked !== bManBlocked) return aManBlocked - bManBlocked;

        const pA = priorityOrder[a.priority || 'NORMAL'];
        const pB = priorityOrder[b.priority || 'NORMAL'];
        if (pA !== pB) return pA - pB;
        return (a.createdAt || 0) - (b.createdAt || 0); 
      });

      setTasks(sortedTasks);
    });
  }, []);

  // --- REALTIME DATA (Dynamic - always live) ---

  useEffect(() => { return onSnapshot(collection(db, 'users'), s => setUsers(s.docs.map(d => ({id:d.id, ...d.data()} as UserData)))); }, []);
  useEffect(() => { return onSnapshot(collection(db, 'roles'), s => setRoles(s.docs.map(d => ({id:d.id, ...d.data()} as Role)))); }, []);
  useEffect(() => { return onSnapshot(collection(db, 'permissions'), s => setPermissions(s.docs.map(d => ({id:d.id, ...d.data()} as Permission)))); }, []);
  useEffect(() => { return onSnapshot(query(collection(db, 'workplaces'), orderBy('value')), s => setWorkplaces(s.docs.map(d => ({id:d.id, value:d.data().value, standardTime:d.data().standardTime} as DBItem)))); }, []);
  useEffect(() => { return onSnapshot(query(collection(db, 'missing_reasons'), orderBy('value')), s => setMissingReasons(s.docs.map(d => ({id:d.id, value:d.data().value} as DBItem)))); }, []);
  useEffect(() => { return onSnapshot(query(collection(db, 'break_schedules')), s => setBreakSchedules(s.docs.map(d => ({id:d.id, ...d.data()} as BreakSchedule)))); }, []);

  useEffect(() => { 
      return onSnapshot(query(collection(db, 'logistics_operations'), orderBy('value')), async (s) => {
          const ops = s.docs.map(d => ({id:d.id, value:d.data().value, standardTime: d.data().standardTime} as DBItem));
          if (ops.length === 0 && !s.metadata.fromCache) {
               const defaults = ['VYKLÁDKA', 'NAKLÁDKA', 'ZASKLADNENIE', 'INTERNÝ PRESUN'];
               const batch = writeBatch(db);
               defaults.forEach(op => batch.set(doc(collection(db, 'logistics_operations')), { value: op, standardTime: 0 }));
               await batch.commit();
          } else {
              setLogisticsOperations(ops);
          }
      }); 
  }, []);


  // --- SMART CACHING LOGIC (Heavy Data Only: Parts & BOM) ---
  const incrementDataVersion = async () => {
      const metaRef = doc(db, 'metadata', 'system');
      try {
          await setDoc(metaRef, { dataVersion: increment(1) }, { merge: true });
      } catch (e) {
          console.error("Version increment failed", e);
      }
  };

  const refreshSmartData = async (inputServerVersion?: number) => {
      try {
          let serverVersion: number;
          if (inputServerVersion !== undefined) {
              serverVersion = inputServerVersion;
          } else {
              const metaRef = doc(db, 'metadata', 'system');
              const metaSnap = await getDoc(metaRef);
              serverVersion = metaSnap.exists() ? (metaSnap.data()?.dataVersion ?? 0) : 0;
          }

          const localVersion = parseInt(localStorage.getItem('cached_data_version') || '-1');
          let loadedFromCache = false;

          if (serverVersion === localVersion && localVersion !== -1) {
              try {
                  const cParts = localStorage.getItem('cached_parts');
                  const cBom = localStorage.getItem('cached_bom');

                  if (cParts && cBom) {
                      setParts(JSON.parse(cParts));
                      setBomItems(JSON.parse(cBom));
                      loadedFromCache = true;
                  }
              } catch (err) {
                  console.warn("Cache parsing failed, falling back to cloud.", err);
              }
          }

          if (!loadedFromCache) {
              const pSnap = await getDocs(query(collection(db, 'parts'), orderBy('value')));
              const bSnap = await getDocs(query(collection(db, 'bom_items'), orderBy('parentPart')));

              const newParts = pSnap.docs.map(d => ({id:d.id, ...d.data()} as DBItem));
              const newBOM = bSnap.docs.map(d => ({id:d.id, ...d.data()} as BOMItem));

              setParts(newParts);
              setBomItems(newBOM);

              localStorage.setItem('cached_parts', JSON.stringify(newParts));
              localStorage.setItem('cached_bom', JSON.stringify(newBOM));
              localStorage.setItem('cached_data_version', serverVersion.toString());
          }
      } catch (e) {
          console.error("Smart Data Load Failed:", e);
      }
  };

  useEffect(() => {
      const metaRef = doc(db, 'metadata', 'system');
      const unsubscribe = onSnapshot(metaRef, (snap) => {
          if (snap.exists()) {
              const data = snap.data();
              const jitter = Math.floor(Math.random() * 10000); 
              setTimeout(() => {
                  refreshSmartData(data.dataVersion);
              }, jitter);
          } else {
              refreshSmartData(0);
          }
      });
      return () => unsubscribe();
  }, []);

  useEffect(() => { const q = query(collection(db, 'part_requests')); return onSnapshot(q, s => setPartRequests(s.docs.map(d => ({id:d.id, ...d.data()} as PartRequest)))); }, []);
  useEffect(() => { const q = query(collection(db, 'bom_requests')); return onSnapshot(q, s => setBomRequests(s.docs.map(d => ({id:d.id, ...d.data()} as BOMRequest)))); }, []);
  // Fix: use the correct 'Notification' interface instead of 'AppNotification'
  useEffect(() => { return onSnapshot(collection(db, 'notifications'), s => setNotifications(s.docs.map(d => ({id:d.id, ...d.data()} as Notification)))); }, []);

  useEffect(() => { 
      const q = query(collection(db, 'system_breaks')); 
      return onSnapshot(q, s => {
          const breaks = s.docs.map(d => ({id:d.id, ...d.data()} as SystemBreak));
          setSystemBreaks(breaks);
          setIsBreakActive(breaks.some(b => b.isActive));
      }); 
  }, []);

  useEffect(() => {
      if (!breakSchedules.length) return;
      const checkTime = () => {
          const now = new Date();
          const hours = String(now.getHours()).padStart(2, '0');
          const minutes = String(now.getMinutes()).padStart(2, '0');
          const currentHM = `${hours}:${minutes}`;

          const matchingSchedule = breakSchedules.find(s => currentHM >= s.start && currentHM < s.end);
          if (matchingSchedule && !isBreakActive) {
              const recentlyCreated = systemBreaks.some(sb => sb.isActive && Math.abs(sb.start - Date.now()) < 60000);
              if (!recentlyCreated) addDoc(collection(db, 'system_breaks'), { start: Date.now(), isActive: true });
          }

          const matchingEnd = breakSchedules.find(s => s.end === currentHM);
          const isInsideAnySchedule = breakSchedules.some(s => currentHM >= s.start && currentHM < s.end);
          if ((matchingEnd || !isInsideAnySchedule) && isBreakActive) {
              const activeBreak = systemBreaks.find(b => b.isActive);
              if (activeBreak) updateDoc(doc(db, 'system_breaks', activeBreak.id), { end: Date.now(), isActive: false });
          }
      };
      const interval = setInterval(checkTime, 10000); 
      return () => clearInterval(interval);
  }, [breakSchedules, isBreakActive, systemBreaks]);


  // --- ACTIONS ---

  const handleLogin = (u: string, r: any) => { setIsAuthenticated(true); setCurrentUser(u); setCurrentUserRole(r); localStorage.setItem('app_user', u); localStorage.setItem('app_role', r); };

  const handleAddUser = async (u: UserData) => { await addDoc(collection(db, 'users'), u); };
  const handleUpdatePassword = async (u: string, p: string) => { const user = users.find(us => us.username === u); if(user) { await updateDoc(doc(db,'users', user.id!), {password: p}); } };
  const handleUpdateUserRole = async (u: string, r: any) => { const user = users.find(us => us.username === u); if(user) { await updateDoc(doc(db,'users', user.id!), {role: r}); } };
  const handleDeleteUser = async (u: string) => { const user = users.find(us => us.username === u); if(user) { await deleteDoc(doc(db,'users', user.id!)); } };

  const handleAddPart = async (v: string, desc?: string) => { 
      await addDoc(collection(db,'parts'), {value:v, description: desc || ''}); 
      await incrementDataVersion();
  };
  const handleBatchAddParts = async (vs: string[]) => { 
      const b=writeBatch(db); 
      vs.forEach(v => {
          const [val, desc] = v.split(';');
          if(val) b.set(doc(collection(db,'parts')), {value:val.trim(), description: desc ? desc.trim() : ''});
      }); 
      await b.commit(); 
      await incrementDataVersion();
  };
  const handleDeletePart = async (id: string) => { 
      await deleteDoc(doc(db,'parts',id)); 
      await incrementDataVersion();
  };
  const handleDeleteAllParts = async () => { 
      const s=await getDocs(collection(db,'parts')); 
      const b=writeBatch(db); 
      s.forEach(d=>b.delete(d.ref)); 
      await b.commit(); 
      await incrementDataVersion();
  };

  const handleAddWorkplace = async (v: string, t?: number) => { 
      await addDoc(collection(db,'workplaces'), {value:v, standardTime:t||0}); 
  };
  const handleBatchAddWorkplaces = async (vs: string[]) => { 
      const b=writeBatch(db); 
      vs.forEach(l=>{const [v,t]=l.split(';'); if(v) b.set(doc(collection(db,'workplaces')), {value:v.trim(), standardTime: parseInt(t)||0})}); 
      await b.commit(); 
  };
  const handleDeleteWorkplace = async (id: string) => { 
      await deleteDoc(doc(db,'workplaces',id)); 
  };
  const handleDeleteAllWorkplaces = async () => { 
      const s=await getDocs(collection(db,'workplaces')); 
      const b=writeBatch(db); 
      s.forEach(d=>b.delete(d.ref)); 
      await b.commit(); 
  };

  const handleAddMissingReason = async (v: string) => { 
      await addDoc(collection(db,'missing_reasons'), {value:v}); 
  };
  const handleDeleteMissingReason = async (id: string) => { 
      await deleteDoc(doc(db,'missing_reasons',id)); 
  };

  const handleAddLogisticsOperation = async (v: string, t?: number) => { 
      await addDoc(collection(db,'logistics_operations'), {value:v, standardTime: t || 0}); 
  };
  const handleDeleteLogisticsOperation = async (id: string) => { 
      await deleteDoc(doc(db,'logistics_operations',id)); 
  };

  const handleDeleteMissingItem = (id: string) => deleteDoc(doc(db,'tasks',id));

  const handleAddBreakSchedule = async (s:string, e:string) => { await addDoc(collection(db,'break_schedules'), {start:s, end:e}); };
  const handleDeleteBreakSchedule = async (id: string) => { await deleteDoc(doc(db,'break_schedules',id)); };

  const handleAddBOMItem = async (p:string, c:string, q:number) => { 
      await addDoc(collection(db,'bom_items'), {parentPart:p, childPart:c, quantity:q}); 
      await incrementDataVersion();
  };
  const handleBatchAddBOMItems = async (vs: string[]) => { 
      const b=writeBatch(db); 
      vs.forEach(l=>{const p=l.split(';'); if(p.length>=3) b.set(doc(collection(db,'bom_items')), {parentPart:p[0].trim(), childPart:p[1].trim(), quantity:parseFloat(p[2].trim().replace(',','.'))})}); 
      await b.commit(); 
      await incrementDataVersion();
  };
  const handleDeleteBOMItem = async (id: string) => { 
      await deleteDoc(doc(db,'bom_items',id)); 
      await incrementDataVersion();
  };
  const handleDeleteAllBOMItems = async () => { 
      const s=await getDocs(collection(db,'bom_items')); 
      const b=writeBatch(db); 
      s.forEach(d=>b.delete(d.ref)); 
      await b.commit(); 
      await incrementDataVersion();
  };

  const handleRequestBOM = async (p: string) => { await addDoc(collection(db,'bom_requests'), {parentPart:p, requestedBy:currentUser, requestedAt:Date.now()}); return true; };
  const handleApproveBOMRequest = (r: BOMRequest) => deleteDoc(doc(db,'bom_requests',r.id));
  const handleRejectBOMRequest = (id: string) => deleteDoc(doc(db,'bom_requests',id));

  const handleAddRole = async (n:string) => {
      const nameUpper = n.toUpperCase();
      if (roles.some(r => r.name === nameUpper)) {
          alert("Rola s týmto názvom už existuje!");
          return;
      }
      await addDoc(collection(db,'roles'), {name:nameUpper, isSystem:false});
  };
  const handleDeleteRole = async (id:string) => { 
      await deleteDoc(doc(db,'roles',id)); 
      const s=await getDocs(query(collection(db,'permissions'), where('roleId','==',id))); 
      const b=writeBatch(db); 
      s.forEach(d=>b.delete(d.ref)); 
      await b.commit(); 
  };
  const handleUpdatePermission = async (pid:string, rname:string, has:boolean) => { 
      const r=roles.find(ro=>ro.name===rname); 
      if(!r)return; 
      if(has) await addDoc(collection(db,'permissions'), {roleId:r.id, permissionName:pid}); 
      else { const p=permissions.find(perm=>perm.roleId===r.id && perm.permissionName===pid); if(p) await deleteDoc(doc(db,'permissions',p.id)); } 
  };

  const handleVerifyAdminPassword = (password: string) => {
      return users.some(u => u.role === 'ADMIN' && u.password === password);
  };

  const handleRequestNewPart = async (p: string) => { await addDoc(collection(db,'part_requests'), {partNumber:p, requestedBy:currentUser, requestedAt:Date.now()}); return true; };
  const handleApprovePartRequest = (req: PartRequest) => { handleAddPart(req.partNumber); deleteDoc(doc(db,'part_requests',req.id)); };
  const handleRejectPartRequest = (id: string) => deleteDoc(doc(db,'part_requests',id));

  const handleAddTask = async (pn: string, wp: string | null, qty: string | null, unit: string | null, prio: PriorityLevel, type: 'production' | 'logistics' = 'production') => {
    const formattedDate = new Date().toLocaleString('sk-SK');
    let fQty = qty || ''; 
    if(unit==='boxes') fQty=`${qty} box`; 
    if(unit==='pallet') fQty=`${qty} pal`;

    let text = `${formattedDate} / ${pn}`;
    if (wp) text += ` / ${wp}`;
    if (fQty) text += ` / Počet: ${fQty}`;

    let finalStandardTime = 0;

    if (type === 'production') {
        const wpObj = workplaces.find(w => w.value === wp);
        finalStandardTime = wpObj?.standardTime || 0;

        if (unit === 'pallet' && qty) {
            const numericQty = parseFloat(qty.replace(',', '.'));
            if (!isNaN(numericQty) && numericQty > 0) {
                finalStandardTime = Math.round(finalStandardTime * numericQty);
            }
        }
    } else if (type === 'logistics') {
        const opObj = logisticsOperations.find(op => op.value === wp); 
        finalStandardTime = opObj?.standardTime || 0;

        if (qty) {
            const numericQty = parseFloat(qty.replace(',', '.'));
            if (!isNaN(numericQty) && numericQty > 0) {
                 finalStandardTime = Math.round(finalStandardTime * numericQty);
            }
        }
    }

    // --- AUTOMATICKÉ 'RIEŠIM' PRE INVENTÚRU ---
    const isInventoryTask = pn === "Počítanie zásob";

    await addDoc(collection(db, 'tasks'), { 
        text: text, 
        partNumber: pn, 
        workplace: wp, 
        quantity: qty, 
        quantityUnit: unit, 
        standardTime: finalStandardTime, 
        isDone:false, 
        priority:prio, 
        createdAt:Date.now(), 
        createdBy:currentUser,
        type: type,
        isInProgress: isInventoryTask,
        inProgressBy: isInventoryTask ? currentUser : null,
        startedAt: isInventoryTask ? Date.now() : null
    });
  };

  const handleUpdateTask = async (id: string, updates: Partial<Task>) => {
    await updateDoc(doc(db, 'tasks', id), updates);
  };

  const handleToggleTask = async (id: string) => {
    const t = tasks.find(x => x.id === id);
    if(t) {
        const newState = !t.isDone;
        await updateDoc(doc(db,'tasks',id), { isDone:newState, status:newState?'completed':null, completionTime:newState?new Date().toLocaleTimeString('sk-SK'):null, completedBy:newState?currentUser:null, completedAt:newState?Date.now():null, isInProgress:false, inProgressBy:null, isBlocked:false, isManualBlocked: false });
    }
  };

  const handleMarkAsIncorrect = async (id: string) => updateDoc(doc(db,'tasks',id), { isDone:true, status:'incorrectly_entered', completionTime:new Date().toLocaleTimeString('sk-SK'), completedBy:currentUser, completedAt:Date.now(), isInProgress:false, inProgressBy:null, isBlocked:false, isManualBlocked: false });
  const handleSetInProgress = async (id: string) => { const t = tasks.find(x=>x.id===id); if(t) updateDoc(doc(db,'tasks',id), { isInProgress:!t.isInProgress, inProgressBy:!t.isInProgress?currentUser:null, startedAt:(!t.isInProgress && !t.startedAt)?Date.now():t.startedAt }); };
  const handleAddNote = (id:string, n:string) => updateDoc(doc(db,'tasks',id), {note:n});
  const handleReleaseTask = (id:string) => updateDoc(doc(db,'tasks',id), {isInProgress:false, inProgressBy:null});
  const handleEditTask = (id:string, txt:string, prio?:PriorityLevel) => updateDoc(doc(db,'tasks',id), {text:txt, priority:prio});
  const handleDeleteTask = (id:string) => deleteDoc(doc(db,'tasks',id));

  const handleToggleMissing = async (id:string, reason?:string) => { 
      const t=tasks.find(x=>x.id===id); 
      if(t) {
          const isMissing = !t.isMissing;
          await updateDoc(doc(db,'tasks',id), { 
              isMissing, 
              missingReportedBy: isMissing?currentUser:null, 
              missingReason: isMissing?(reason||'Iné'):null,
              isInProgress: false, 
              inProgressBy: null,
              isBlocked: false,
              isManualBlocked: false
          });
          if (isMissing) {
              await addDoc(collection(db, 'notifications'), {
                  partNumber: t.partNumber || 'Unknown',
                  reason: reason || 'Iné',
                  reportedBy: currentUser,
                  timestamp: Date.now()
              });
          }
      } 
  };

  const handleClearNotification = (id: string) => deleteDoc(doc(db, 'notifications', id));

  const handleToggleBlock = async (id: string) => {
      const t=tasks.find(x=>x.id===id);
      if(t) {
          const isBlocked = !t.isBlocked;
          const hist = t.inventoryHistory ? [...t.inventoryHistory] : [];
          if(isBlocked) hist.push({start:Date.now()}); else { const last=hist[hist.length-1]; if(last && !last.end) last.end=Date.now(); }
          updateDoc(doc(db,'tasks',id), { isBlocked, inventoryHistory:hist });
      }
  };

  const handleToggleManualBlock = async (id: string) => {
      const t = tasks.find(x => x.id === id);
      if (t) {
          const newState = !t.isManualBlocked;
          await updateDoc(doc(db, 'tasks', id), { 
              isManualBlocked: newState,
              // When unblocking, reset createdAt so it jumps to top of its priority group
              createdAt: !newState ? Date.now() : t.createdAt,
              isInProgress: false,
              inProgressBy: null
          });
      }
  };

  const handleArchiveTasks = async () => {
      const q = query(collection(db,'tasks'), where('isDone','==',true), limit(1000));
      const s = await getDocs(q);
      const toArchive = s.docs.filter(d => !d.data().completedAt || d.data().completedAt < (Date.now() - 86400000));
      if(toArchive.length===0) return {success:true, count:0, message:"Žiadne staré úlohy."};
      const b=writeBatch(db);
      toArchive.forEach(d => { b.set(doc(collection(db,'archived_tasks')), {...d.data(), archivedAt:Date.now()}); b.delete(d.ref); });
      await b.commit();
      return {success:true, count:toArchive.length};
  };
  const fetchArchivedTasks = async () => (await getDocs(collection(db,'archived_tasks'))).docs.map(d=>({id:d.id, ...d.data()} as Task));

  const handleUpdateSystemConfig = async (newConfig: Partial<SystemConfig>) => {
      const configRef = doc(db, 'system_data', 'config');
      await setDoc(configRef, newConfig, { merge: true });
  };

  return (
    <div className={`min-h-screen bg-gray-900 flex flex-col ${!isAuthenticated ? 'items-center justify-center' : ''}`}>
      {!isAuthenticated ? (
        <LoginScreen onLoginSuccess={handleLogin} users={users} systemConfig={systemConfig} />
      ) : (
        <PartSearchScreen 
          currentUser={currentUser} currentUserRole={currentUserRole} onLogout={handleLogout}
          tasks={tasks} onAddTask={handleAddTask} onToggleTask={handleToggleTask} onEditTask={handleEditTask} onDeleteTask={handleDeleteTask}
          onUpdateTask={handleUpdateTask}
          onToggleMissing={handleToggleMissing} onSetInProgress={handleSetInProgress} onToggleBlock={handleToggleBlock} onToggleManualBlock={handleToggleManualBlock} onMarkAsIncorrect={handleMarkAsIncorrect} onAddNote={handleAddNote} onReleaseTask={handleReleaseTask}
          users={users} onAddUser={handleAddUser} onUpdatePassword={handleUpdatePassword} onUpdateUserRole={handleUpdateUserRole} onDeleteUser={handleDeleteUser}
          parts={parts} workplaces={workplaces} missingReasons={missingReasons} logisticsOperations={logisticsOperations}
          onAddPart={handleAddPart} onBatchAddParts={handleBatchAddParts} onDeletePart={handleDeletePart} onDeleteAllParts={handleDeleteAllParts}
          onAddWorkplace={handleAddWorkplace} onBatchAddWorkplaces={handleBatchAddWorkplaces} onDeleteWorkplace={handleDeleteWorkplace} onDeleteAllWorkplaces={handleDeleteAllWorkplaces}
          onAddMissingReason={handleAddMissingReason} onDeleteMissingReason={handleDeleteMissingReason}
          onAddLogisticsOperation={handleAddLogisticsOperation} onDeleteLogisticsOperation={handleDeleteLogisticsOperation}
          partRequests={partRequests} onRequestPart={handleRequestNewPart} onApprovePartRequest={handleApprovePartRequest} onRejectPartRequest={handleRejectPartRequest}
          onArchiveTasks={handleArchiveTasks} 
          onFetchArchivedTasks={fetchArchivedTasks}
          onDeleteMissingItem={handleDeleteMissingItem}
          breakSchedules={breakSchedules} systemBreaks={systemBreaks} isBreakActive={isBreakActive} onAddBreakSchedule={handleAddBreakSchedule} onDeleteBreakSchedule={handleDeleteBreakSchedule}
          bomItems={bomItems} bomRequests={bomRequests} onAddBOMItem={handleAddBOMItem} onBatchAddBOMItems={handleBatchAddBOMItems} onDeleteBOMItem={handleDeleteBOMItem} onDeleteAllBOMItems={handleDeleteAllBOMItems} onRequestBOM={handleRequestBOM} onApproveBOMRequest={handleApproveBOMRequest} onRejectBOMRequest={handleRejectBOMRequest}
          roles={roles} permissions={permissions} onAddRole={handleAddRole} onDeleteRole={handleDeleteRole} onUpdatePermission={handleUpdatePermission}
          onVerifyAdminPassword={handleVerifyAdminPassword}
          notifications={notifications} onClearNotification={handleClearNotification}
          installPrompt={deferredPrompt} onInstallApp={handleInstallApp}
          systemConfig={systemConfig} onUpdateSystemConfig={handleUpdateSystemConfig}
          dbLoadWarning={dbLoadWarning} 
        />
      )}
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect, useCallback } from 'react';
import PartNumberInput from './PartNumberInput';
import TaskList from './TaskList';
import SettingsTab from './SettingsTab';
import AnalyticsTab from './AnalyticsTab';
import MissingItemsTab from './MissingItemsTab';
import LogisticsCenterTab from './LogisticsCenterTab';
import InventoryTab from './InventoryTab';
import PermissionsTab from './PermissionsTab';
import { UserData, DBItem, PartRequest, BreakSchedule, SystemBreak, BOMItem, BOMRequest, Role, Permission, Task, Notification as AppNotification, PriorityLevel, SystemConfig } from '../App';
import { useLanguage } from './LanguageContext';

declare var XLSX: any;

interface PartSearchScreenProps {
  currentUser: string;
  currentUserRole: 'ADMIN' | 'USER' | 'LEADER';
  onLogout: () => void;
  tasks: Task[];
  onAddTask: (partNumber: string, workplace: string | null, quantity: string | null, quantityUnit: string | null, priority: PriorityLevel, type?: 'production' | 'logistics') => void; 
  onUpdateTask: (id: string, updates: Partial<Task>) => void;
  onToggleTask: (id: string) => void;
  onMarkAsIncorrect: (id: string) => void;
  onEditTask: (id: string, newText: string, newPriority?: PriorityLevel) => void;
  onDeleteTask: (id: string) => void;
  onToggleMissing: (id: string, reason?: string) => void; 
  onSetInProgress: (id: string) => void;
  onToggleBlock: (id: string) => void; 
  onToggleManualBlock: (id: string) => void;
  onAddNote: (id: string, note: string) => void;
  onDeleteMissingItem: (id: string) => void;
  onReleaseTask: (id: string) => void;
  users: UserData[];
  onAddUser: (user: UserData) => void;
  onUpdatePassword: (username: string, newPass: string) => void;
  onUpdateUserRole: (username: string, newRole: any) => void;
  onDeleteUser: (username: string) => void;
  parts: DBItem[];
  workplaces: DBItem[];
  missingReasons: DBItem[];
  onAddPart: (val: string, desc?: string) => void;
  onBatchAddParts: (vals: string[]) => void;
  onDeletePart: (id: string) => void;
  onDeleteAllParts: () => void;
  onAddWorkplace: (val: string, time?: number) => void;
  onBatchAddWorkplaces: (vals: string[]) => void;
  onDeleteWorkplace: (id: string) => void;
  onDeleteAllWorkplaces: () => void;
  onAddMissingReason: (val: string) => void;
  onDeleteMissingReason: (id: string) => void;
  logisticsOperations: DBItem[];
  onAddLogisticsOperation: (val: string, time?: number) => void; 
  onDeleteLogisticsOperation: (id: string) => void;
  partRequests: PartRequest[];
  onRequestPart: (part: string) => Promise<boolean>;
  onApprovePartRequest: (req: PartRequest) => void;
  onRejectPartRequest: (id: string) => void;
  onArchiveTasks: () => Promise<{ success: boolean; count?: number; error?: string; message?: string }>;
  onFetchArchivedTasks: () => Promise<Task[]>;
  breakSchedules: BreakSchedule[];
  systemBreaks: SystemBreak[];
  isBreakActive: boolean;
  onAddBreakSchedule: (start: string, end: string) => void;
  onDeleteBreakSchedule: (id: string) => void;
  bomItems: BOMItem[];
  bomRequests: BOMRequest[];
  onAddBOMItem: (parent: string, child: string, qty: number) => void;
  onBatchAddBOMItems: (vals: string[]) => void;
  onDeleteBOMItem: (id: string) => void;
  onDeleteAllBOMItems: () => void;
  onRequestBOM: (parent: string) => Promise<boolean>;
  onApproveBOMRequest: (req: BOMRequest) => void;
  onRejectBOMRequest: (id: string) => void;
  roles: Role[];
  permissions: Permission[];
  onAddRole: (name: string) => void;
  onDeleteRole: (id: string) => void;
  onUpdatePermission: (permissionId: string, roleName: string, hasPermission: boolean) => void;
  onVerifyAdminPassword: (password: string) => boolean;
  notifications: AppNotification[];
  onClearNotification: (id: string) => void;
  installPrompt: any;
  onInstallApp: () => void;
  systemConfig: SystemConfig;
  onUpdateSystemConfig: (config: Partial<SystemConfig>) => void;
  dbLoadWarning: boolean;
}

